    fn reference_prefix(until_step: u32) -> Vec<Telescope> {
        (1..=until_step).map(Telescope::reference).collect()
    }

    fn reference_library(until_step: u32) -> Library {
        let mut library = Vec::new();
        for telescope in reference_prefix(until_step) {
            library.push(LibraryEntry::from_telescope(&telescope, &library));
        }
        library
    }

    fn library_until(until_step: u32) -> Library {
        let mut library = Vec::new();
        for step in 1..=until_step {
            let telescope = Telescope::reference(step);
            library.push(LibraryEntry::from_telescope(&telescope, &library));
        }
        library
    }

    fn reference_history_until(
        until_step: u32,
    ) -> (Library, Vec<DiscoveryRecord>, Vec<(u32, u32)>) {
        let mut library = Vec::new();
        let mut history = Vec::new();
        let mut nu_history = Vec::new();

        for step in 1..=until_step {
            let telescope = Telescope::reference(step);
            let nu = structural_nu(&telescope, &library, &nu_history).total;
            history.push(DiscoveryRecord::new(
                step,
                nu,
                u32::try_from(telescope.kappa()).expect("kappa exceeded u32"),
            ));
            nu_history.push((step, nu));
            library.push(LibraryEntry::from_telescope(&telescope, &library));
        }

        (library, history, nu_history)
    }

    fn history_from_prefix(
        prefix: &[Telescope],
    ) -> (Library, Vec<DiscoveryRecord>, Vec<(u32, u32)>) {
        let mut library = Vec::new();
        let mut history = Vec::new();
        let mut nu_history = Vec::new();

        for (index, telescope) in prefix.iter().enumerate() {
            let step = u32::try_from(index + 1).expect("step index exceeded u32");
            let nu = structural_nu(telescope, &library, &nu_history).total;
            history.push(DiscoveryRecord::new(
                step,
                nu,
                u32::try_from(telescope.kappa()).expect("kappa exceeded u32"),
            ));
            nu_history.push((step, nu));
            library.push(LibraryEntry::from_telescope(telescope, &library));
        }

        (library, history, nu_history)
    }

    fn claim_long_rerun_v3_divergent_prefix() -> Vec<Telescope> {
        fn formation_pi(domain: Expr, codomain: Expr) -> ClauseRec {
            ClauseRec::new(
                ClauseRole::Formation,
                Expr::Pi(Box::new(domain), Box::new(codomain)),
            )
        }

        let mut prefix = reference_prefix(9);
        for lib_ref in 8..=11 {
            prefix.push(Telescope::new(vec![
                formation_pi(Expr::Var(1), Expr::Var(1)),
                formation_pi(Expr::Var(1), Expr::Var(1)),
                formation_pi(Expr::Lib(lib_ref), Expr::Var(1)),
            ]));
        }
        prefix
    }

    fn claim_long_rerun_v3_hybrid_prefix(divergent_from_step: Option<u32>) -> Vec<Telescope> {
        let mut prefix = reference_prefix(13);
        let divergent = claim_long_rerun_v3_divergent_prefix();
        if let Some(start_step) = divergent_from_step {
            assert!(
                (10..=13).contains(&start_step),
                "hybrid divergent suffix must start inside steps 10..13"
            );
            for step_index in start_step..=13 {
                let slot = usize::try_from(step_index - 1).expect("step index exceeded usize");
                prefix[slot] = divergent[slot].clone();
            }
        }
        prefix
    }

    #[derive(Clone, Debug, Eq, PartialEq)]
    struct DirectTerminalAssessment {
        generated_candidate_count: usize,
        admitted_candidate_count: usize,
        bound: Option<PrefixBound>,
        can_clear_bar: bool,
    }

    fn direct_terminal_assessment_from_raw_options(
        step_index: u32,
        library: &Library,
        admissibility: StrictAdmissibility,
        objective_bar: Rational,
        nu_history: &[(u32, u32)],
        prefix_telescope: &Telescope,
        last_clause_options: &[ClauseRec],
    ) -> DirectTerminalAssessment {
        let mut admitted_candidate_count = 0usize;
        let mut bound: Option<PrefixBound> = None;
        let mut can_clear_bar = false;

        for clause in last_clause_options {
            let mut telescope = prefix_telescope.clone();
            telescope.clauses.push(clause.clone());
            if !passes_connectivity(library, &telescope) {
                continue;
            }

            let admissibility_decision =
                assess_strict_admissibility(step_index, library, &telescope, admissibility);
            if !admissibility_decision.is_admitted() {
                continue;
            }

            admitted_candidate_count += 1;
            let exact_nu = u16::try_from(structural_nu(&telescope, library, nu_history).total)
                .expect("nu exceeded u16");
            let clause_kappa_used = u16::try_from(telescope.kappa()).expect("kappa exceeded u16");
            let bit_kappa_used =
                u16::try_from(telescope.bit_cost()).expect("bit cost exceeded u16");
            if let Some(bound) = bound.as_mut() {
                bound.absorb_completion(exact_nu, clause_kappa_used, bit_kappa_used);
            } else {
                bound = Some(PrefixBound::singleton(
                    exact_nu,
                    clause_kappa_used,
                    bit_kappa_used,
                ));
            }
            can_clear_bar |=
                Rational::new(i64::from(exact_nu), i64::from(clause_kappa_used)) >= objective_bar;
        }

        DirectTerminalAssessment {
            generated_candidate_count: last_clause_options.len(),
            admitted_candidate_count,
            bound,
            can_clear_bar,
        }
    }

    fn direct_terminal_assessment_from_terminal_candidates(
        step_index: u32,
        library: &Library,
        admissibility: StrictAdmissibility,
        objective_bar: Rational,
        nu_history: &[(u32, u32)],
        prefix_telescope: &Telescope,
        terminal_clauses: &super::TerminalPrefixClauseCandidates<'_>,
    ) -> DirectTerminalAssessment {
        let mut generated_candidate_count = 0usize;
        let mut admitted_candidate_count = 0usize;
        let mut bound: Option<PrefixBound> = None;
        let mut can_clear_bar = false;

        let mut assess_clause =
            |clause: &ClauseRec,
             _connectivity_facts: Option<&TerminalClauseConnectivityFacts>,
             cached_admissibility_decision: Option<&AdmissibilityDecision>| {
                generated_candidate_count += 1;
                let mut telescope = prefix_telescope.clone();
                telescope.clauses.push(clause.clone());

                if !passes_connectivity(library, &telescope) {
                    return;
                }

                let admissibility_decision =
                    cached_admissibility_decision.cloned().unwrap_or_else(|| {
                        assess_strict_admissibility(step_index, library, &telescope, admissibility)
                    });
                if !admissibility_decision.is_admitted() {
                    return;
                }

                admitted_candidate_count += 1;
                let exact_nu = u16::try_from(structural_nu(&telescope, library, nu_history).total)
                    .expect("nu exceeded u16");
                let clause_kappa_used =
                    u16::try_from(telescope.kappa()).expect("kappa exceeded u16");
                let bit_kappa_used =
                    u16::try_from(telescope.bit_cost()).expect("bit cost exceeded u16");
                if let Some(bound) = bound.as_mut() {
                    bound.absorb_completion(exact_nu, clause_kappa_used, bit_kappa_used);
                } else {
                    bound = Some(PrefixBound::singleton(
                        exact_nu,
                        clause_kappa_used,
                        bit_kappa_used,
                    ));
                }
                can_clear_bar |= Rational::new(i64::from(exact_nu), i64::from(clause_kappa_used))
                    >= objective_bar;
            };

        match terminal_clauses {
            super::TerminalPrefixClauseCandidates::General(clauses) => {
                for clause in clauses {
                    assess_clause(
                        clause.clause,
                        clause.connectivity_facts,
                        clause.cached_admissibility_decision.as_ref(),
                    );
                }
            }
            super::TerminalPrefixClauseCandidates::ClaimAdmittedOpenBand(clauses) => {
                for clause in clauses {
                    assess_clause(clause.clause, clause.connectivity_facts, None);
                }
            }
        }

        DirectTerminalAssessment {
            generated_candidate_count,
            admitted_candidate_count,
            bound,
            can_clear_bar,
        }
    }

