    fn current_claim_step_fifteen_partial_prefix_wall_summary() -> LateStepPartialPrefixWallSummary
    {
        let reference_prefix = Telescope::new(Telescope::reference(15).clauses[..7].to_vec());
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            14,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 14 should build");
        let prefix = claim_steps
            .into_iter()
            .map(|step| step.telescope)
            .collect::<Vec<_>>();
        let (library, _, _) = history_from_prefix(&prefix);

        super::start_partial_prefix_bound_prune_capture();
        let _step = profile_step_from_reference_prefix(15, SearchProfile::DesktopClaimShadow);
        let captures = super::finish_partial_prefix_bound_prune_capture();

        let mut summary = LateStepPartialPrefixWallSummary {
            capture_count: captures.len(),
            ..LateStepPartialPrefixWallSummary::default()
        };
        for capture in captures {
            *summary
                .remaining_clause_slot_counts
                .entry(capture.remaining_clause_slots)
                .or_insert(0) += 1;

            let historical_reanchor =
                HistoricalReanchorSummary::from_telescope(&library, &capture.prefix_telescope);
            *summary
                .matched_clause_counts
                .entry(historical_reanchor.matched_clause_count())
                .or_insert(0) += 1;
            let mismatch_position = capture
                .prefix_telescope
                .clauses
                .iter()
                .zip(reference_prefix.clauses.iter())
                .position(|(left, right)| left != right);
            *summary
                .first_mismatch_position_counts
                .entry(mismatch_position)
                .or_insert(0) += 1;
            *summary
                .slot_mismatch_position_counts
                .entry((capture.remaining_clause_slots, mismatch_position))
                .or_insert(0) += 1;
        }

        summary
    }

    fn current_claim_step_fifteen_partial_prefix_clause_zero_one_label(
        position: usize,
        clause: &ClauseRec,
    ) -> &'static str {
        match position {
            0 => {
                if matches!(
                    &clause.expr,
                    Expr::Next(body) if matches!(body.as_ref(), Expr::Var(1))
                ) {
                    "reference"
                } else if matches!(
                    &clause.expr,
                    Expr::Next(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Flat(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "claim_flat_domain"
                } else if matches!(
                    &clause.expr,
                    Expr::Next(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Eventually(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "claim_eventual_domain"
                } else if matches!(
                    &clause.expr,
                    Expr::Next(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Sharp(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "demo_sharp_domain"
                } else if matches!(
                    &clause.expr,
                    Expr::Next(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Next(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "demo_next_domain"
                } else {
                    "unclassified"
                }
            }
            1 => {
                if matches!(
                    &clause.expr,
                    Expr::Eventually(body) if matches!(body.as_ref(), Expr::Var(1))
                ) {
                    "reference"
                } else if matches!(
                    &clause.expr,
                    Expr::Eventually(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Sharp(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "claim_sharp_codomain"
                } else if matches!(
                    &clause.expr,
                    Expr::Eventually(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Next(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "claim_next_codomain"
                } else if matches!(
                    &clause.expr,
                    Expr::Eventually(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Flat(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "demo_flat_codomain"
                } else if matches!(
                    &clause.expr,
                    Expr::Eventually(body)
                        if matches!(
                            body.as_ref(),
                            Expr::Eventually(inner) if matches!(inner.as_ref(), Expr::Var(1))
                        )
                ) {
                    "demo_eventually_codomain"
                } else {
                    "unclassified"
                }
            }
            _ => "out_of_scope",
        }
    }

    fn current_claim_step_fifteen_remaining_two_partial_prefix_clause_zero_one_pair_counts()
    -> BTreeMap<(Option<usize>, &'static str, &'static str), usize> {
        let reference_prefix = Telescope::new(Telescope::reference(15).clauses[..7].to_vec());

        super::start_partial_prefix_bound_prune_capture();
        let _step = profile_step_from_reference_prefix(15, SearchProfile::DesktopClaimShadow);
        let captures = super::finish_partial_prefix_bound_prune_capture();

        let mut pair_counts = BTreeMap::new();
        for capture in captures
            .into_iter()
            .filter(|capture| capture.remaining_clause_slots == 2)
        {
            let mismatch = capture
                .prefix_telescope
                .clauses
                .iter()
                .zip(reference_prefix.clauses.iter())
                .position(|(left, right)| left != right);
            let clause_zero = current_claim_step_fifteen_partial_prefix_clause_zero_one_label(
                0,
                &capture.prefix_telescope.clauses[0],
            );
            let clause_one = current_claim_step_fifteen_partial_prefix_clause_zero_one_label(
                1,
                &capture.prefix_telescope.clauses[1],
            );
            *pair_counts
                .entry((mismatch, clause_zero, clause_one))
                .or_insert(0usize) += 1;
        }

        pair_counts
    }

    fn current_claim_step_fifteen_remaining_two_partial_prefix_pair_counts_outside_reference_demo_flat_tradeoff_ladder()
    -> BTreeMap<(Option<usize>, &'static str, &'static str), usize> {
        current_claim_step_fifteen_remaining_two_partial_prefix_clause_zero_one_pair_counts()
            .into_iter()
            .filter(|((mismatch, clause_zero, clause_one), _count)| {
                !(*mismatch == Some(1_usize)
                    && *clause_zero == "reference"
                    && *clause_one == "demo_flat_codomain")
            })
            .collect()
    }

    fn current_claim_step_fifteen_remaining_two_partial_prefix_mismatch_counts_outside_reference_demo_flat_tradeoff_ladder()
    -> BTreeMap<Option<usize>, usize> {
        let mut mismatch_counts = BTreeMap::new();
        for ((mismatch, _clause_zero, _clause_one), count) in
            current_claim_step_fifteen_remaining_two_partial_prefix_pair_counts_outside_reference_demo_flat_tradeoff_ladder()
        {
            *mismatch_counts.entry(mismatch).or_insert(0usize) += count;
        }
        mismatch_counts
    }

    fn current_claim_step_fifteen_remaining_two_partial_prefix_surface_totals_outside_reference_demo_flat_tradeoff_ladder()
    -> BTreeMap<&'static str, usize> {
        let mut surface_totals = BTreeMap::new();
        for ((mismatch, _clause_zero, _clause_one), count) in
            current_claim_step_fifteen_remaining_two_partial_prefix_pair_counts_outside_reference_demo_flat_tradeoff_ladder()
        {
            let surface_label = match mismatch {
                Some(0_usize) => "mismatch_zero_claim_domain_surface",
                Some(1_usize) => "mismatch_one_claim_safe_surface",
                _ => "reference_reference_tail",
            };
            *surface_totals.entry(surface_label).or_insert(0usize) += count;
        }
        surface_totals
    }

    fn current_claim_step_fifteen_reference_reference_tail_mismatch_position_counts()
    -> BTreeMap<usize, usize> {
        current_claim_step_fifteen_remaining_two_partial_prefix_clause_zero_one_pair_counts()
            .into_iter()
            .filter_map(|((mismatch, clause_zero, clause_one), count)| {
                (clause_zero == "reference"
                    && clause_one == "reference"
                    && matches!(mismatch, Some(2_usize) | Some(3_usize)))
                .then_some((
                    mismatch.expect(
                        "reference/reference tail should stay localized to mismatch 2 or 3",
                    ),
                    count,
                ))
            })
            .collect()
    }

    fn current_claim_step_fifteen_reference_reference_tail_clause_four_counts()
    -> BTreeMap<(usize, &'static str), usize> {
        let counts = current_claim_step_fifteen_remaining_two_partial_prefix_bridge_family_counts();
        let mut clause_four_counts = BTreeMap::new();
        for ((mismatch, clause_zero, clause_one, _clause_two, clause_four, _clause_five), count) in
            counts
        {
            if clause_zero != "reference" || clause_one != "reference" {
                continue;
            }
            let Some(mismatch) = mismatch else {
                continue;
            };
            if !matches!(mismatch, 2_usize | 3_usize) {
                continue;
            }
            *clause_four_counts
                .entry((mismatch, clause_four))
                .or_insert(0usize) += count;
        }

        clause_four_counts
    }

