        let reference_prefix = Telescope::new(Telescope::reference(15).clauses[..7].to_vec());
        let mismatch = prefix_telescope
            .clauses
            .iter()
            .zip(reference_prefix.clauses.iter())
            .position(|(left, right)| left != right);
