    fn late_step_exact_prune_family_summary(
        prefix: &[Telescope],
        step_index: u32,
        limit: usize,
    ) -> LateStepExactPruneFamilySummary {
        let surface = late_step_pruned_terminal_surface_from_prefix(prefix, step_index, limit);
        let mut family_counts = BTreeMap::new();
        let mut cached_bound_count = 0usize;
        for work_item in &surface.pruned_terminal_prefixes {
            let mut summary_cache = surface.prefix_legality_cache.clone();
            let summary = summary_cache.terminal_prefix_completion_summary(&work_item.signature);
            let mut cache = surface.prefix_legality_cache.clone();
            let terminal_clauses = super::terminal_prefix_clause_candidates(
                surface.step_index,
                &surface.library,
                surface.admissibility,
                &work_item.signature,
                work_item.next_clauses(&surface.clause_catalog),
                work_item.next_clause_connectivity_facts(&surface.clause_catalog),
                work_item.next_clause_nu_facts(&surface.clause_catalog),
                &mut cache,
                None,
            );
            let filtered_direct = direct_terminal_assessment_from_terminal_candidates(
                surface.step_index,
                &surface.library,
                surface.admissibility,
                surface.objective_bar,
                &surface.nu_history,
                &work_item.prefix_telescope,
                &terminal_clauses,
            );
            let raw_direct = direct_terminal_assessment_from_raw_options(
                surface.step_index,
                &surface.library,
                surface.admissibility,
                surface.objective_bar,
                &surface.nu_history,
                &work_item.prefix_telescope,
                work_item.next_clauses(&surface.clause_catalog),
            );

            assert_eq!(raw_direct.bound, filtered_direct.bound);
            assert_eq!(
                raw_direct.admitted_candidate_count,
                filtered_direct.admitted_candidate_count
            );
            assert!(!filtered_direct.can_clear_bar);
            assert!(!raw_direct.can_clear_bar);

            let key = (
                filtered_direct.admitted_candidate_count,
                filtered_direct.bound.map(|bound| bound.nu_upper_bound),
                filtered_direct.bound.map(|bound| bound.clause_kappa_used),
            );
            *family_counts.entry(key).or_insert(0) += 1;
            if let Some(summary) = summary {
                if summary.bound.is_some() {
                    cached_bound_count += 1;
                }
                assert_eq!(summary.bound, filtered_direct.bound);
            }
        }

        LateStepExactPruneFamilySummary {
            raw_generated_surface: surface.raw_generated_surface,
            roots_seen: surface.roots_seen,
            roots_enqueued: surface.roots_enqueued,
            partial_prefix_bound_prunes: surface.partial_prefix_bound_prunes,
            captured_prefixes: surface.pruned_terminal_prefixes.len(),
            cached_bound_count,
            family_counts,
        }
    }

    fn late_step_zero_admitted_failure_summary(
        prefix: &[Telescope],
        step_index: u32,
        limit: usize,
    ) -> LateStepZeroAdmittedFailureSummary {
        let surface = late_step_pruned_terminal_surface_from_prefix(prefix, step_index, limit);
        let mut summary = LateStepZeroAdmittedFailureSummary {
            captured_prefixes: surface.pruned_terminal_prefixes.len(),
            ..LateStepZeroAdmittedFailureSummary::default()
        };
        for work_item in &surface.pruned_terminal_prefixes {
            let mut disconnected = 0usize;
            let mut trivially_derivable = 0usize;
            let mut other_exact_legality = 0usize;
            let mut structural_debt_cap = 0usize;
            let mut admitted = 0usize;
            for clause in work_item.next_clauses(&surface.clause_catalog) {
                summary.generated_candidates += 1;
                let mut telescope = work_item.prefix_telescope.clone();
                telescope.clauses.push(clause.clone());
                if !passes_connectivity(&surface.library, &telescope) {
                    disconnected += 1;
                    summary.disconnected_candidates += 1;
                    continue;
                }

                let decision = assess_strict_admissibility(
                    surface.step_index,
                    &surface.library,
                    &telescope,
                    surface.admissibility,
                );
                if decision.is_admitted() {
                    admitted += 1;
                    continue;
                }

                *summary
                    .reason_counts
                    .entry(decision.reason.clone())
                    .or_insert(0) += 1;
                match decision.class {
                    AdmissibilityDecisionClass::RejectedByExactLegality
                        if decision.reason == "trivially_derivable" =>
                    {
                        trivially_derivable += 1;
                        summary.trivially_derivable_rejections += 1;
                    }
                    AdmissibilityDecisionClass::RejectedByExactLegality => {
                        other_exact_legality += 1;
                        summary.other_exact_legality_rejections += 1;
                    }
                    AdmissibilityDecisionClass::RejectedByStructuralDebtCap => {
                        structural_debt_cap += 1;
                        summary.structural_debt_cap_rejections += 1;
                    }
                    AdmissibilityDecisionClass::AdmittedDeprioritized
                    | AdmissibilityDecisionClass::AdmittedFocusAligned => {
                        unreachable!("rejected decision should not be admitted");
                    }
                }
            }

            assert_eq!(
                admitted, 0,
                "captured exact-prune prefixes should stay zero-admitted on the current surface"
            );
            if disconnected > 0
                && trivially_derivable == 0
                && other_exact_legality == 0
                && structural_debt_cap == 0
            {
                summary.all_disconnected_prefixes += 1;
            } else if disconnected == 0
                && trivially_derivable > 0
                && other_exact_legality == 0
                && structural_debt_cap == 0
            {
                summary.trivially_derivable_only_prefixes += 1;
            } else if disconnected > 0
                && trivially_derivable > 0
                && other_exact_legality == 0
                && structural_debt_cap == 0
            {
                summary.mixed_disconnect_and_trivial_prefixes += 1;
            } else {
                summary.other_rejection_prefixes += 1;
            }
        }

        summary
    }

    fn late_step_terminal_connectivity_summary(
        prefix: &[Telescope],
        step_index: u32,
        limit: usize,
    ) -> LateStepTerminalConnectivitySummary {
        let surface = late_step_pruned_terminal_surface_from_prefix(prefix, step_index, limit);
        let mut summary = LateStepTerminalConnectivitySummary {
            captured_prefixes: surface.pruned_terminal_prefixes.len(),
            ..LateStepTerminalConnectivitySummary::default()
        };

        for work_item in &surface.pruned_terminal_prefixes {
            let mut cache = surface.prefix_legality_cache.clone();
            let connectivity_facts = work_item
                .next_clause_connectivity_facts(&surface.clause_catalog)
                .expect("captured claim terminal prefixes should still expose connectivity facts");
            for (clause, connectivity_facts) in work_item
                .next_clauses(&surface.clause_catalog)
                .iter()
                .zip(connectivity_facts.iter())
            {
                summary.generated_candidates += 1;
                let decision = cache
                    .terminal_connectivity_with_facts(
                        &work_item.signature,
                        &surface.library,
                        clause,
                        Some(connectivity_facts),
                    )
                    .expect("captured claim terminal prefix should still reuse connectivity facts");
                match decision {
                    TerminalConnectivityDecision::PruneDisconnected => {
                        summary.prune_disconnected_candidates += 1;
                    }
                    TerminalConnectivityDecision::NeedsFallback => {
                        summary.needs_fallback_candidates += 1;
                    }
                    TerminalConnectivityDecision::KeepWithoutFallback => {
                        summary.keep_without_fallback_candidates += 1;
                    }
                }

                let mut telescope = work_item.prefix_telescope.clone();
                telescope.clauses.push(clause.clone());
                let witness = analyze_connectivity(&surface.library, &telescope);
                if !witness.connected {
                    summary.structurally_disconnected_candidates += 1;
                } else if witness.historical_reanchor {
                    summary.structurally_connected_via_historical_reanchor_candidates += 1;
                } else if !witness.references_active_window && !witness.self_contained {
                    summary.structurally_connected_but_unqualified_candidates += 1;
                }
            }
        }

        summary
    }

