    #[test]
    fn current_claim_step_fifteen_zero_admitted_connectivity_surface_reports_reanchor_prefix_progress()
     {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let mut matched_prefix_counts = BTreeMap::new();
        let mut first_mismatch_counts = BTreeMap::new();
        let mut full_prefix_matches = 0usize;

        for work_item in &surface.pruned_terminal_prefixes {
            let summary = HistoricalReanchorSummary::from_telescope(
                &surface.library,
                &work_item.prefix_telescope,
            );
            *matched_prefix_counts
                .entry(summary.matched_clause_count())
                .or_insert(0usize) += 1;
            *first_mismatch_counts
                .entry(summary.first_mismatch_position())
                .or_insert(0usize) += 1;
            if summary.matched_clause_count() == work_item.prefix_telescope.clauses.len() {
                full_prefix_matches += 1;
            }
        }

        assert_eq!(
            matched_prefix_counts,
            [(1_usize, 291_usize), (2, 1494), (3, 486),]
                .into_iter()
                .collect(),
            "captured step-15 zero-admitted prefixes should now split into one narrow clause-1 side band plus the existing clause-2 and clause-3 historical-reanchor misses"
        );
        assert_eq!(
            first_mismatch_counts,
            [(Some(1_usize), 291_usize), (Some(2), 1494), (Some(3), 486),]
                .into_iter()
                .collect(),
            "the captured step-15 exact-prune surface should now preserve the repaired clause-0, clause-4, and clause-5 prefixes, while clause-1 contributes a new narrow side-pocket miss band ahead of the older clause-2 and clause-3 losses"
        );
        assert_eq!(full_prefix_matches, 0);
    }

    #[test]
    fn current_claim_step_fifteen_exact_prune_capture_stops_before_clause_six_temporal_variants() {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let admissibility = strict_admissibility_for_mode(
            15,
            2,
            &surface.library,
            AdmissibilityMode::DesktopClaimShadow,
        );
        let clause_catalog = build_clause_catalog(
            EnumerationContext::from_admissibility(&surface.library, admissibility),
            8,
        );
        let six_clause_prefix = Telescope::new(Telescope::reference(15).clauses[..6].to_vec());
        let six_clause_signature = PrefixSignature::new(15, &surface.library, &six_clause_prefix);
        let mut six_clause_cache = PrefixLegalityCache::default();
        assert!(six_clause_cache.insert_root(
            six_clause_signature.clone(),
            8,
            &surface.library,
            &six_clause_prefix,
            admissibility,
            LateFamilySurface::ClaimGeneric
        ));
        let six_clause_work_item = create_online_prefix_work_item(
            8,
            six_clause_prefix.clone(),
            six_clause_signature,
            &surface.library,
            admissibility,
            &clause_catalog,
            &mut six_clause_cache,
        );
        assert_eq!(six_clause_work_item.remaining_clause_slots, 2);

        let mut clause_six_match_counts = BTreeMap::new();
        let clause_six_prefixes = six_clause_work_item
            .next_clauses(&clause_catalog)
            .iter()
            .map(|clause| {
                let mut prefix = six_clause_prefix.clone();
                prefix.clauses.push(clause.clone());
                let summary = HistoricalReanchorSummary::from_telescope(&surface.library, &prefix);
                *clause_six_match_counts
                    .entry(summary.matched_clause_count())
                    .or_insert(0usize) += 1;
                prefix
            })
            .collect::<Vec<_>>();
        assert_eq!(clause_six_prefixes.len(), 3);
        assert_eq!(
            clause_six_match_counts,
            [(6_usize, 2_usize), (7, 1)].into_iter().collect(),
            "after the first six temporal-shell clauses are fixed, the claim lane should keep exactly one clause-6 historical-reanchor continuation and two non-reanchor claim variants"
        );
        assert!(
            clause_six_prefixes.iter().all(|prefix| surface
                .pruned_terminal_prefixes
                .iter()
                .all(|work_item| work_item.prefix_telescope != *prefix)),
            "the captured step-15 exact-prune surface should already stop before the clause-6 temporal-shell variants"
        );

        let reference_clause_six_prefix =
            Telescope::new(Telescope::reference(15).clauses[..7].to_vec());
        let clause_six_terminal_decisions = clause_six_prefixes
            .iter()
            .map(|prefix| {
                let summary = HistoricalReanchorSummary::from_telescope(&surface.library, prefix);
                let signature = PrefixSignature::new(15, &surface.library, prefix);
                let mut cache = PrefixLegalityCache::default();
                assert!(cache.insert_root(
                    signature.clone(),
                    8,
                    &surface.library,
                    prefix,
                    admissibility,
                    LateFamilySurface::ClaimGeneric
                ));
                let work_item = create_online_prefix_work_item(
                    8,
                    prefix.clone(),
                    signature.clone(),
                    &surface.library,
                    admissibility,
                    &clause_catalog,
                    &mut cache,
                );
                assert_eq!(work_item.remaining_clause_slots, 1);
                let connectivity_facts = work_item
                    .next_clause_connectivity_facts(&clause_catalog)
                    .expect("clause-6 temporal variants should still expose cached terminal connectivity facts");
                let decisions = work_item
                    .next_clauses(&clause_catalog)
                    .iter()
                    .zip(connectivity_facts.iter())
                    .map(|(clause, facts)| {
                        cache
                            .terminal_connectivity_with_facts(
                                &signature,
                                &surface.library,
                                clause,
                                Some(facts),
                            )
                            .expect(
                                "clause-6 temporal variants should still classify all terminal continuations",
                            )
                    })
                    .collect::<Vec<_>>();
                (prefix.clone(), summary.matched_clause_count(), decisions)
            })
            .collect::<Vec<_>>();
        let reference_decisions = clause_six_terminal_decisions
            .iter()
            .find(|(prefix, matched_clause_count, _)| {
                *matched_clause_count == 7 && *prefix == reference_clause_six_prefix
            })
            .expect("the reference clause-6 temporal prefix should still be present");
        assert_eq!(
            reference_decisions
                .2
                .iter()
                .filter(|decision| **decision == TerminalConnectivityDecision::KeepWithoutFallback)
                .count(),
            1,
            "the exact clause-6 temporal prefix should still expose exactly one historical-reanchor terminal continuation"
        );
        assert!(
            clause_six_terminal_decisions
                .iter()
                .filter(|(_, matched_clause_count, _)| *matched_clause_count == 6)
                .all(|(_, _, decisions)| decisions
                    .iter()
                    .all(|decision| *decision == TerminalConnectivityDecision::NeedsFallback)),
            "the two non-reference clause-6 claim variants should still stay outside historical reanchor even though they have already escaped the captured exact-prune surface"
        );
    }

    #[test]
    fn current_claim_step_fifteen_single_early_temporal_variants_still_need_fallback_on_exact_suffix()
     {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let reference_prefix = Telescope::new(Telescope::reference(15).clauses[..7].to_vec());
        let mut isolated_prefix_counts = BTreeMap::new();

        for position in 0..6 {
            let isolated_prefixes = surface
                .pruned_terminal_prefixes
                .iter()
                .filter(|work_item| {
                    let clauses = &work_item.prefix_telescope.clauses;
                    clauses[..position] == reference_prefix.clauses[..position]
                        && clauses[position] != reference_prefix.clauses[position]
                        && clauses[position + 1..] == reference_prefix.clauses[position + 1..]
                })
                .collect::<Vec<_>>();
            isolated_prefix_counts.insert(position, isolated_prefixes.len());
            let expected_isolated_count = if position == 1 {
                1
            } else if (2..=3).contains(&position) {
                2
            } else {
                0
            };
            assert_eq!(
                isolated_prefixes.len(),
                expected_isolated_count,
                "clause positions 0, 4, and 5 should stay repaired out of the captured temporal-shell surface, while clause 1 now contributes one isolated anchor-11 side-pocket deviation and positions 2 and 3 should still expose exactly two isolated claim-only deviations on the otherwise exact seven-clause prefix"
            );

            for work_item in isolated_prefixes {
                let summary = HistoricalReanchorSummary::from_telescope(
                    &surface.library,
                    &work_item.prefix_telescope,
                );
                assert_eq!(summary.matched_clause_count(), position);
                assert_eq!(summary.first_mismatch_position(), Some(position));

                let terminal_clauses = work_item.next_clauses(&surface.clause_catalog);
                assert_eq!(terminal_clauses.len(), 3);
                let mut cache = surface.prefix_legality_cache.clone();
                let connectivity_facts = work_item
                    .next_clause_connectivity_facts(&surface.clause_catalog)
                    .expect("isolated temporal prefixes should still expose cached terminal connectivity facts");
                let decisions = terminal_clauses
                    .iter()
                    .zip(connectivity_facts.iter())
                    .map(|(clause, facts)| {
                        cache
                            .terminal_connectivity_with_facts(
                                &work_item.signature,
                                &surface.library,
                                clause,
                                Some(facts),
                            )
                            .expect(
                                "isolated temporal prefixes should still classify every terminal continuation",
                            )
                    })
                    .collect::<Vec<_>>();
                assert!(
                    decisions
                        .iter()
                        .all(|decision| *decision == TerminalConnectivityDecision::NeedsFallback),
                    "a single early claim-only temporal deviation should already keep all terminal continuations outside historical reanchor on the otherwise exact suffix"
                );

                let direct = direct_terminal_assessment_from_raw_options(
                    surface.step_index,
                    &surface.library,
                    surface.admissibility,
                    surface.objective_bar,
                    &surface.nu_history,
                    &work_item.prefix_telescope,
                    terminal_clauses,
                );
                assert_eq!(
                    direct,
                    DirectTerminalAssessment {
                        generated_candidate_count: 3,
                        admitted_candidate_count: 0,
                        bound: None,
                        can_clear_bar: false,
                    },
                    "isolated early temporal deviations should still be zero-admitted even when the rest of the prefix is exact"
                );
            }
        }

        assert_eq!(
            isolated_prefix_counts,
            [(0_usize, 0_usize), (1, 1), (2, 2), (3, 2), (4, 0), (5, 0),]
                .into_iter()
                .collect(),
            "the captured step-15 exact-prune surface should now exclude the repaired clause-0, clause-4, and clause-5 temporal deviations while still containing the new isolated clause-1 side-pocket deviation and the remaining isolated clause-2 and clause-3 deviations"
        );
    }

    #[test]
    fn current_claim_step_fifteen_each_early_temporal_variant_blocks_all_later_claim_suffixes() {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);

        for position in 0..6 {
            let mut variant_counts = Vec::<(ClauseRec, usize)>::new();
            for work_item in surface.pruned_terminal_prefixes.iter().filter(|work_item| {
                HistoricalReanchorSummary::from_telescope(
                    &surface.library,
                    &work_item.prefix_telescope,
                )
                .first_mismatch_position()
                    == Some(position)
            }) {
                let mismatched_clause = work_item.prefix_telescope.clauses[position].clone();
                if let Some((_, count)) = variant_counts
                    .iter_mut()
                    .find(|(existing_clause, _)| *existing_clause == mismatched_clause)
                {
                    *count += 1;
                } else {
                    variant_counts.push((mismatched_clause, 1));
                }
            }

            let mut observed_counts = variant_counts
                .into_iter()
                .map(|(_, count)| count)
                .collect::<Vec<_>>();
            observed_counts.sort_unstable();
            let expected_counts = if position == 1 {
                vec![291]
            } else if position == 2 {
                vec![747, 747]
            } else if position == 3 {
                vec![243, 243]
            } else {
                Vec::new()
            };
            assert_eq!(
                observed_counts, expected_counts,
                "clause positions 0, 4, and 5 should stay repaired out of the captured surface, while clause 1 now carries one narrow side-pocket variant and the remaining isolated claim-only variants at positions 2 and 3 should still stay captured across every later claim suffix combination before the clause-6 boundary"
            );
        }
    }

    #[test]
    fn current_claim_step_fifteen_isolated_temporal_variants_expose_clause_local_forced_reanchor_recovery_surface()
     {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let reference_prefix = Telescope::new(Telescope::reference(15).clauses[..7].to_vec());
        let mut forced_recovery_counts = BTreeMap::new();

        for position in 0..6 {
            let isolated_prefixes = surface
                .pruned_terminal_prefixes
                .iter()
                .filter(|work_item| {
                    let clauses = &work_item.prefix_telescope.clauses;
                    clauses[..position] == reference_prefix.clauses[..position]
                        && clauses[position] != reference_prefix.clauses[position]
                        && clauses[position + 1..] == reference_prefix.clauses[position + 1..]
                })
                .collect::<Vec<_>>();
            let mut forced_keep_without_fallback = 0usize;
            let mut forced_admitted = 0usize;
            let mut forced_bar_clearers = 0usize;

            for work_item in isolated_prefixes {
                let connectivity_summary = ConnectivitySummary::from_telescope(
                    &surface.library,
                    &work_item.prefix_telescope,
                );
                for clause in work_item.next_clauses(&surface.clause_catalog) {
                    let decision =
                        connectivity_summary.terminal_decision(&surface.library, clause, true);
                    if !matches!(decision, ConnectivityTerminalDecision::KeepWithoutFallback) {
                        continue;
                    }
                    forced_keep_without_fallback += 1;

                    let mut telescope = work_item.prefix_telescope.clone();
                    telescope.clauses.push(clause.clone());
                    let admissibility_decision = assess_strict_admissibility(
                        surface.step_index,
                        &surface.library,
                        &telescope,
                        surface.admissibility,
                    );
                    if !admissibility_decision.is_admitted() {
                        continue;
                    }

                    forced_admitted += 1;
                    let exact_nu = u16::try_from(
                        structural_nu(&telescope, &surface.library, &surface.nu_history).total,
                    )
                    .expect("nu exceeded u16");
                    let clause_kappa_used =
                        u16::try_from(telescope.kappa()).expect("kappa exceeded u16");
                    if Rational::new(i64::from(exact_nu), i64::from(clause_kappa_used))
                        >= surface.objective_bar
                    {
                        forced_bar_clearers += 1;
                    }
                }
            }

            forced_recovery_counts.insert(
                position,
                (
                    forced_keep_without_fallback,
                    forced_admitted,
                    forced_bar_clearers,
                ),
            );
        }

        assert_eq!(
            forced_recovery_counts,
            [
                (0_usize, (0_usize, 0_usize, 0_usize)),
                (1, (3, 3, 3)),
                (2, (6, 6, 6)),
                (3, (6, 6, 6)),
                (4, (0, 0, 0)),
                (5, (0, 0, 0)),
            ]
            .into_iter()
            .collect(),
            "the repaired clause-0, clause-4, and clause-5 variants should stay out of the captured isolated surface, while the new clause-1 side-pocket and the remaining isolated clause-2 and clause-3 deviations would still become fully admitted, bar-clearing local surfaces if the missing clause-local reanchor evidence were restored"
        );
    }

    #[test]
    fn current_claim_step_fifteen_exact_terminal_only_isolated_recovery_still_reopens_clause_two_three_rivals()
     {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let reference_prefix = Telescope::new(Telescope::reference(15).clauses[..7].to_vec());
        let reference_terminal = Telescope::reference(15)
            .clauses
            .last()
            .cloned()
            .expect("reference step 15 should have a terminal clause");
        let canonical_bit_kappa = u16::try_from(pen_core::encode::telescope_bit_cost(
            &Telescope::reference(15),
        ))
        .expect("bit cost exceeded u16");
        let canonical_rank = super::acceptance_rank_for_telescope(
            surface.objective_bar,
            &Telescope::reference(15),
            103,
            canonical_bit_kappa,
            8,
        )
        .expect("reference step-15 telescope should clear the bar");
        let mut recovered_counts = BTreeMap::new();
        let mut recovered_profiles = BTreeMap::new();

        for position in 0..6 {
            let isolated_prefixes = surface
                .pruned_terminal_prefixes
                .iter()
                .filter(|work_item| {
                    let clauses = &work_item.prefix_telescope.clauses;
                    clauses[..position] == reference_prefix.clauses[..position]
                        && clauses[position] != reference_prefix.clauses[position]
                        && clauses[position + 1..] == reference_prefix.clauses[position + 1..]
                })
                .collect::<Vec<_>>();
            let mut clears = 0usize;
            let mut profiles = BTreeSet::new();

            for work_item in isolated_prefixes {
                let mut telescope = work_item.prefix_telescope.clone();
                telescope.clauses.push(reference_terminal.clone());
                let admissibility_decision = assess_strict_admissibility(
                    surface.step_index,
                    &surface.library,
                    &telescope,
                    surface.admissibility,
                );
                if !admissibility_decision.is_admitted() {
                    continue;
                }

                let exact_nu = u16::try_from(
                    structural_nu(&telescope, &surface.library, &surface.nu_history).total,
                )
                .expect("nu exceeded u16");
                let bit_kappa_used =
                    u16::try_from(pen_core::encode::telescope_bit_cost(&telescope))
                        .expect("bit cost exceeded u16");
                let clause_kappa_used =
                    u16::try_from(telescope.kappa()).expect("kappa exceeded u16");
                let accept_rank = super::acceptance_rank_for_telescope(
                    surface.objective_bar,
                    &telescope,
                    exact_nu,
                    bit_kappa_used,
                    clause_kappa_used,
                )
                .expect("reference-terminal isolated recovery should clear the bar");
                if accept_rank < canonical_rank {
                    clears += 1;
                }
                profiles.insert((exact_nu, accept_rank.overshoot.clone()));
            }

            recovered_counts.insert(position, clears);
            recovered_profiles.insert(position, profiles);
        }

        assert_eq!(
            recovered_counts,
            [(0_usize, 0_usize), (1, 0), (2, 2), (3, 2), (4, 0), (5, 0),]
                .into_iter()
                .collect(),
            "isolated exact-terminal recovery would still produce stronger-than-canonical local rivals at clause positions 2 and 3, while positions 4 and 5 stay on the canonical primary profile"
        );
        assert_eq!(
            recovered_profiles,
            [
                (0_usize, BTreeSet::new()),
                (
                    1,
                    [(103_u16, Rational::new(115657, 21112))]
                        .into_iter()
                        .collect()
                ),
                (
                    2,
                    [(89_u16, Rational::new(78711, 21112))]
                        .into_iter()
                        .collect()
                ),
                (
                    3,
                    [(88_u16, Rational::new(9509, 2639))].into_iter().collect()
                ),
                (4, BTreeSet::new()),
                (5, BTreeSet::new()),
            ]
            .into_iter()
            .collect(),
            "exact-terminal-only local recovery would still create stronger isolated clause-2 and clause-3 rivals, while the new clause-1 side pocket only restores the same-primary 103/8 reference-terminal profile and clause-4 and clause-5 stay repaired out of the captured isolated surface"
        );
    }

    #[test]
