    #[test]
    fn current_claim_step_fifteen_clause_four_side_pocket_capture_stays_tiny_and_noncanonical() {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let reference_terminal = Telescope::reference(15)
            .clauses
            .last()
            .cloned()
            .expect("reference step 15 should have a terminal clause");
        let next_lift_terminal = ClauseRec::new(
            ClauseRole::Formation,
            Expr::Pi(
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(Expr::Next(
                    Box::new(Expr::Var(1)),
                )))))),
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(Expr::Var(1)))))),
            ),
        );
        let eventual_lift_terminal = ClauseRec::new(
            ClauseRole::Formation,
            Expr::Pi(
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(
                    Expr::Eventually(Box::new(Expr::Var(1))),
                ))))),
                Box::new(Expr::Next(Box::new(Expr::Eventually(Box::new(Expr::Var(
                    1,
                )))))),
            ),
        );
        let anchor = surface
            .admissibility
            .historical_anchor_ref
            .expect("step 15 should still expose a historical anchor");
        let exact_argument_clause = ClauseRec::new(
            ClauseRole::Introduction,
            Expr::Lam(Box::new(Expr::App(
                Box::new(Expr::Lib(anchor + 1)),
                Box::new(Expr::Next(Box::new(Expr::Var(1)))),
            ))),
        );
        let claim_clause_two_variants = [
            (
                "claim_flat_domain",
                ClauseRec::new(
                    ClauseRole::Formation,
                    Expr::Pi(
                        Box::new(Expr::Next(Box::new(Expr::Flat(Box::new(Expr::Var(1)))))),
                        Box::new(Expr::Eventually(Box::new(Expr::Var(1)))),
                    ),
                ),
            ),
            (
                "claim_sharp_codomain",
                ClauseRec::new(
                    ClauseRole::Formation,
                    Expr::Pi(
                        Box::new(Expr::Next(Box::new(Expr::Var(1)))),
                        Box::new(Expr::Eventually(Box::new(Expr::Sharp(Box::new(
                            Expr::Var(1),
                        ))))),
                    ),
                ),
            ),
        ];
        let mut capture_counts = BTreeMap::<&'static str, usize>::new();
        let mut exact_terminal_profiles =
            BTreeMap::<&'static str, BTreeSet<(u16, Rational)>>::new();
        let mut forced_admitted_counts = BTreeMap::<&'static str, usize>::new();
        let mut forced_bar_clearing_counts = BTreeMap::<&'static str, usize>::new();
        let mut forced_winner_counts = BTreeMap::<&'static str, (usize, usize, usize)>::new();

        for work_item in &surface.pruned_terminal_prefixes {
            if work_item.prefix_telescope.clauses[3] != exact_argument_clause {
                continue;
            }
            let label = claim_clause_two_variants
                .iter()
                .find_map(|(label, clause)| {
                    (*clause == work_item.prefix_telescope.clauses[2]).then_some(*label)
                })
                .expect("exact-argument side-pocket capture should stay restricted to the two claim clause-2 variants");
            *capture_counts.entry(label).or_insert(0) += 1;

            let mut recovered = work_item.prefix_telescope.clone();
            recovered.clauses.push(reference_terminal.clone());
            let admissibility_decision = assess_strict_admissibility(
                surface.step_index,
                &surface.library,
                &recovered,
                surface.admissibility,
            );
            if admissibility_decision.is_admitted() {
                let exact_nu = u16::try_from(
                    structural_nu(&recovered, &surface.library, &surface.nu_history).total,
                )
                .expect("nu exceeded u16");
                let bit_kappa_used =
                    u16::try_from(pen_core::encode::telescope_bit_cost(&recovered))
                        .expect("bit cost exceeded u16");
                let clause_kappa_used =
                    u16::try_from(recovered.kappa()).expect("kappa exceeded u16");
                let accept_rank = super::acceptance_rank_for_telescope(
                    surface.objective_bar,
                    &recovered,
                    exact_nu,
                    bit_kappa_used,
                    clause_kappa_used,
                )
                .expect("the exact-argument side pocket should still clear the bar under exact-terminal-only local recovery");
                exact_terminal_profiles
                    .entry(label)
                    .or_default()
                    .insert((exact_nu, accept_rank.overshoot));
            }

            let connectivity_summary =
                ConnectivitySummary::from_telescope(&surface.library, &work_item.prefix_telescope);
            let mut forced_ranks = Vec::new();
            for clause in work_item.next_clauses(&surface.clause_catalog) {
                let decision =
                    connectivity_summary.terminal_decision(&surface.library, clause, true);
                if !matches!(decision, ConnectivityTerminalDecision::KeepWithoutFallback) {
                    continue;
                }

                let mut telescope = work_item.prefix_telescope.clone();
                telescope.clauses.push(clause.clone());
                let admissibility_decision = assess_strict_admissibility(
                    surface.step_index,
                    &surface.library,
                    &telescope,
                    surface.admissibility,
                );
                if !admissibility_decision.is_admitted() {
                    continue;
                }
                *forced_admitted_counts.entry(label).or_insert(0) += 1;

                let exact_nu = u16::try_from(
                    structural_nu(&telescope, &surface.library, &surface.nu_history).total,
                )
                .expect("nu exceeded u16");
                let bit_kappa_used =
                    u16::try_from(pen_core::encode::telescope_bit_cost(&telescope))
                        .expect("bit cost exceeded u16");
                let clause_kappa_used =
                    u16::try_from(telescope.kappa()).expect("kappa exceeded u16");
                let Some(accept_rank) = super::acceptance_rank_for_telescope(
                    surface.objective_bar,
                    &telescope,
                    exact_nu,
                    bit_kappa_used,
                    clause_kappa_used,
                ) else {
                    continue;
                };
                *forced_bar_clearing_counts.entry(label).or_insert(0) += 1;
                forced_ranks.push((clause.clone(), accept_rank));
            }

            if let Some((best_clause, _)) = forced_ranks
                .iter()
                .min_by(|left, right| left.1.cmp(&right.1))
            {
                let winners = forced_winner_counts
                    .entry(label)
                    .or_insert((0usize, 0usize, 0usize));
                if *best_clause == reference_terminal {
                    winners.0 += 1;
                } else if *best_clause == next_lift_terminal {
                    winners.1 += 1;
                } else if *best_clause == eventual_lift_terminal {
                    winners.2 += 1;
                }
            }
        }

        assert_eq!(
            capture_counts,
            [
                ("claim_flat_domain", 42_usize),
                ("claim_sharp_codomain", 42_usize)
            ]
            .into_iter()
            .collect(),
            "the clause-4 twin side-pocket reland should stay tiny relative to the broader clause-2/3 family even after the newer clause-1 side-pocket reland triples those captured bridge-pocket contexts"
        );
        assert_eq!(
            exact_terminal_profiles,
            [
                (
                    "claim_flat_domain",
                    [
                        (89_u16, Rational::new(78711, 21112)),
                        (103_u16, Rational::new(115657, 21112)),
                    ]
                    .into_iter()
                    .collect()
                ),
                (
                    "claim_sharp_codomain",
                    [
                        (89_u16, Rational::new(78711, 21112)),
                        (103_u16, Rational::new(115657, 21112)),
                    ]
                    .into_iter()
                    .collect()
                ),
            ]
            .into_iter()
            .collect(),
            "the reopened clause-4 side pocket should still stay noncanonical under exact-terminal recovery: it only produces the old unsafe 89/8 rival plus the canonical-primary 103/8 tie-clean pocket"
        );
        assert_eq!(
            forced_admitted_counts,
            [
                ("claim_flat_domain", 126_usize),
                ("claim_sharp_codomain", 126_usize)
            ]
            .into_iter()
            .collect()
        );
        assert_eq!(
            forced_bar_clearing_counts,
            [
                ("claim_flat_domain", 126_usize),
                ("claim_sharp_codomain", 126_usize)
            ]
            .into_iter()
            .collect()
        );
        assert_eq!(
            forced_winner_counts,
            [
                ("claim_flat_domain", (0_usize, 22_usize, 20_usize)),
                ("claim_sharp_codomain", (0_usize, 21_usize, 21_usize)),
            ]
            .into_iter()
            .collect(),
            "even the tiny reopened clause-4 twin side pockets should still route only to non-reference terminal winners under forced reanchor"
        );
    }

    #[test]
    fn step_thirteen_divergence_reopens_operator_bundle_claim_debt_before_the_admitted_step_fourteen_failure_family()
     {
        let reference_prefix = claim_long_rerun_v3_hybrid_prefix(None);
        let divergent_prefix = claim_long_rerun_v3_hybrid_prefix(Some(13));
        let reference_step_thirteen = &reference_prefix[12];
        let divergent_step_thirteen = &divergent_prefix[12];

        assert_eq!(*reference_step_thirteen, Telescope::reference(13));
        assert_eq!(reference_step_thirteen.kappa(), 7);
        assert_eq!(
            reference_step_thirteen.lib_refs(),
            [11_u32, 12_u32].into_iter().collect()
        );
        assert_eq!(divergent_step_thirteen.kappa(), 3);
        assert_eq!(
            divergent_step_thirteen.lib_refs(),
            [11_u32].into_iter().collect()
        );

        let (reference_library, reference_history, _) = history_from_prefix(&reference_prefix);
        let (divergent_library, divergent_history, _) = history_from_prefix(&divergent_prefix);
        let reference_step_thirteen_record = reference_history
            .iter()
            .find(|record| record.step_index == 13)
            .expect("reference step 13 should exist");
        let divergent_step_thirteen_record = divergent_history
            .iter()
            .find(|record| record.step_index == 13)
            .expect("divergent step 13 should exist");

        assert_eq!(reference_step_thirteen_record.kappa, 7);
        assert_eq!(reference_step_thirteen_record.nu, 46);
        assert_eq!(divergent_step_thirteen_record.kappa, 3);
        assert_eq!(divergent_step_thirteen_record.nu, 29);

        let reference_entry = reference_library
            .last()
            .expect("reference step 13 library entry should exist");
        let divergent_entry = divergent_library
            .last()
            .expect("divergent step 13 library entry should exist");
        assert!(reference_entry.capabilities.has_metric);
        assert_eq!(reference_entry.library_refs, 2);
        assert!(!divergent_entry.capabilities.has_metric);
        assert_eq!(divergent_entry.library_refs, 1);

        let reference_debt = summarize_structural_debt(&reference_library, 2);
        let divergent_debt = summarize_structural_debt(&divergent_library, 2);
        assert_eq!(reference_debt.operator_bundle_entries, 1);
        assert!(!reference_debt.requires_operator_bundle_package());
        assert!(reference_debt.requires_hilbert_functional_package());
        assert_eq!(divergent_debt.operator_bundle_entries, 0);
        assert!(divergent_debt.requires_operator_bundle_package());
        assert!(!divergent_debt.requires_hilbert_functional_package());

        let reference_step_open = claim_step_open_from_prefix(&reference_prefix, 14);
        let divergent_step_open = claim_step_open_from_prefix(&divergent_prefix, 14);
        assert!(!reference_step_open.package_flags.operator_bundle);
        assert!(reference_step_open.package_flags.hilbert_functional);
        assert!(divergent_step_open.package_flags.operator_bundle);
        assert!(!divergent_step_open.package_flags.hilbert_functional);

        let reference_summary =
            late_step_exact_prune_family_summary(&reference_prefix, 14, usize::MAX);
        let divergent_summary =
            late_step_exact_prune_family_summary(&divergent_prefix, 14, usize::MAX);
        assert!(!reference_summary.family_counts.contains_key(&(
            3_usize,
            Some(50_u16),
            Some(9_u16)
        )));
        assert!(!reference_summary.family_counts.contains_key(&(
            3_usize,
            Some(51_u16),
            Some(9_u16)
        )));
        assert_eq!(
            divergent_summary
                .family_counts
                .get(&(3_usize, Some(50_u16), Some(9_u16))),
            Some(&729_usize)
        );
        assert_eq!(
            divergent_summary
                .family_counts
                .get(&(3_usize, Some(51_u16), Some(9_u16))),
            Some(&1458_usize)
        );
    }

    #[test]
    fn step_thirteen_divergence_is_the_first_step_fourteen_failure_cutover() {
        let variants = [
            (
                "reference",
                None,
                true,
                12027_usize,
                1458_usize,
                4374_usize,
                0_usize,
                [((0_usize, None, None), 4374_usize)]
                    .into_iter()
                    .collect::<BTreeMap<_, _>>(),
            ),
            (
                "diverge_from_13",
                Some(13),
                false,
                2271_usize,
                1515_usize,
                6561_usize,
                2187_usize,
                [
                    ((0_usize, None, None), 4374_usize),
                    ((3_usize, Some(50_u16), Some(9_u16)), 729_usize),
                    ((3_usize, Some(51_u16), Some(9_u16)), 1458_usize),
                ]
                .into_iter()
                .collect::<BTreeMap<_, _>>(),
            ),
            (
                "diverge_from_12",
                Some(12),
                false,
                2271_usize,
                1515_usize,
                6561_usize,
                2187_usize,
                [
                    ((0_usize, None, None), 4374_usize),
                    ((3_usize, Some(45_u16), Some(9_u16)), 729_usize),
                    ((3_usize, Some(46_u16), Some(9_u16)), 1458_usize),
                ]
                .into_iter()
                .collect::<BTreeMap<_, _>>(),
            ),
            (
                "diverge_from_11",
                Some(11),
                false,
                2271_usize,
                1515_usize,
                6561_usize,
                2187_usize,
                [
                    ((0_usize, None, None), 4374_usize),
                    ((3_usize, Some(39_u16), Some(9_u16)), 729_usize),
                    ((3_usize, Some(40_u16), Some(9_u16)), 1458_usize),
                ]
                .into_iter()
                .collect::<BTreeMap<_, _>>(),
            ),
            (
                "diverge_from_10",
                Some(10),
                false,
                2271_usize,
                1515_usize,
                6561_usize,
                2187_usize,
                [
                    ((0_usize, None, None), 4374_usize),
                    ((3_usize, Some(40_u16), Some(9_u16)), 729_usize),
                    ((3_usize, Some(41_u16), Some(9_u16)), 1458_usize),
                ]
                .into_iter()
                .collect::<BTreeMap<_, _>>(),
            ),
        ];

        for (
            label,
            divergent_from_step,
            expect_search_ok,
            expected_raw_generated_surface,
            expected_partial_prefix_bound_prunes,
            expected_captured_prefixes,
            expected_cached_bound_count,
            expected_family_counts,
        ) in variants
        {
            let prefix = claim_long_rerun_v3_hybrid_prefix(divergent_from_step);
            let outcome = search_bootstrap_from_prefix_for_profile_with_runtime(
                &prefix,
                14,
                2,
                SearchProfile::DesktopClaimShadow,
                crate::diversify::FrontierRuntimeLimits::unlimited(),
            );
            let summary = late_step_exact_prune_family_summary(&prefix, 14, usize::MAX);
            assert_eq!(
                outcome.is_ok(),
                expect_search_ok,
                "{label} changed whether step 14 can still complete"
            );
            assert_eq!(
                summary.raw_generated_surface, expected_raw_generated_surface,
                "{label} changed the raw step-14 surface width"
            );
            assert_eq!(
                summary.roots_seen, 3,
                "{label} changed the promoted late-step root count"
            );
            assert_eq!(
                summary.roots_enqueued, 3,
                "{label} changed the enqueued late-step root count"
            );
            assert_eq!(
                summary.partial_prefix_bound_prunes, expected_partial_prefix_bound_prunes,
                "{label} changed the exact partial-prefix prune total"
            );
            assert_eq!(
                summary.captured_prefixes, expected_captured_prefixes,
                "{label} changed the full captured remaining-one prune surface"
            );
            assert_eq!(
                summary.cached_bound_count, expected_cached_bound_count,
                "{label} changed the number of cached compact bounds on the captured prune surface"
            );
            assert_eq!(
                summary.family_counts, expected_family_counts,
                "{label} changed the captured exact-prune family split"
            );
        }
    }

    #[test]
    fn divergent_step_thirteen_history_cannot_be_repaired_by_forcing_local_operator_band() {
        let prefix = claim_long_rerun_v3_hybrid_prefix(Some(10));
        let (library, history, nu_history) = history_from_prefix(&prefix[..12]);
        let structural_debt = summarize_structural_debt(&library, 2);
        let admissibility =
            strict_admissibility_for_mode(13, 2, &library, AdmissibilityMode::DesktopClaimShadow);
        let objective_bar = compute_bar(2, 13, &history).bar;
        let forced_operator_band = StrictAdmissibility {
            min_clause_kappa: 7,
            max_clause_kappa: 7,
            max_expr_nodes: 7,
            max_path_dimension: 0,
            include_trunc: false,
            include_modal: false,
            include_temporal: false,
            ..admissibility
        };
        let mut demo_step_budget = None;
        let mut demo_narrative = None;
        let mut progress_observer = None;

        assert_eq!(admissibility.min_clause_kappa, 3);
        assert_eq!(admissibility.max_clause_kappa, 3);
        assert_eq!(structural_debt.differential_entries, 2);
        assert_eq!(structural_debt.differential_coupled_entries, 2);
        assert_eq!(structural_debt.curvature_entries, 0);

        let discovery = discover_realistic_shadow_candidates(
            13,
            &library,
            &history,
            structural_debt,
            forced_operator_band,
            structural_debt.retention_policy(),
            objective_bar,
            &nu_history,
            &mut demo_step_budget,
            std::time::Instant::now(),
            &mut demo_narrative,
            &mut progress_observer,
        )
        .expect("forced step-13 operator-band discovery should still run");

        assert!(
            discovery.claim_root_seeding.roots_seen > 0,
            "the forced local repair should still enumerate step-13 operator-band roots"
        );
        assert_eq!(
            discovery.claim_root_seeding.roots_enqueued, 0,
            "the already-divergent step-10..12 history should not have a surviving local step-13 repair root"
        );
        assert_eq!(
            discovery.claim_root_seeding.roots_rejected_by_exact_screen,
            discovery.claim_root_seeding.roots_seen
        );
        assert_eq!(
            discovery.partial_prefix_bound_prunes,
            discovery.claim_root_seeding.roots_seen
        );
        assert!(
            discovery.candidates.is_empty(),
            "forcing a local step-13 operator band should not synthesize a new surviving candidate under the divergent history"
        );
    }

    #[test]
    fn divergent_step_thirteen_acceptance_prefers_step_fourteen_viable_tied_candidate() {
        let prefix = claim_long_rerun_v3_hybrid_prefix(Some(10));
        let (library, history, _) = history_from_prefix(&prefix[..12]);
        let mut progress_observer = None;
        let step = search_next_step_internal(
            13,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut progress_observer,
            false,
        )
        .expect("step 13 should still build");

        let accepted_candidate = step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.candidate_hash == step.accepted.candidate_hash)
            .expect("accepted step-13 candidate should still be retained");
        let accepted_rank = acceptance_rank(step.objective_bar, accepted_candidate)
            .expect("accepted step-13 candidate should still clear the bar");
        let tied_candidates = step
            .retained_candidates
            .iter()
            .filter_map(|candidate| {
                acceptance_rank(step.objective_bar, candidate).map(|rank| (candidate, rank))
            })
            .filter(|(_, rank)| crate::branch_bound::same_primary_rank_tier(rank, &accepted_rank))
            .map(|(candidate, _)| candidate)
            .collect::<Vec<_>>();
        assert_eq!(
            tied_candidates.len(),
            2,
            "the divergent step-13 surface should still expose the primary-rank viability split"
        );

        let viable_hashes = tied_candidates
            .iter()
            .filter_map(|candidate| {
                claim_candidate_keeps_next_step_alive(
                    13,
                    2,
                    &library,
                    &history,
                    AdmissibilityMode::DesktopClaimShadow,
                    crate::diversify::FrontierRuntimeLimits::unlimited(),
                    candidate,
                )
                .then_some(candidate.candidate_hash.clone())
            })
            .collect::<Vec<_>>();
        assert_eq!(
            viable_hashes.len(),
            1,
            "exactly one tied step-13 candidate should keep step 14 alive"
        );
        assert_eq!(
            step.accepted.candidate_hash, viable_hashes[0],
            "the widened step-13 selector should now keep the tied viable shell on the divergent history too"
        );

        let repaired_acceptance = select_acceptance_for_step(
            13,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            step.objective_bar,
            &step.retained_candidates,
            true,
        )
        .expect("claim acceptance should still select a bar clearer");
        assert_eq!(
            repaired_acceptance.accepted.candidate_hash, viable_hashes[0],
            "claim acceptance should pick the tied step-13 shell that preserves next-step viability"
        );
    }

    #[test]
    fn claim_step_nine_same_primary_fork_prefers_the_guarded_axiomatic_bundle() {
        let step = profile_step_from_reference_prefix(9, SearchProfile::DesktopClaimShadow);
        let guarded_step = profile_step_from_reference_prefix(9, SearchProfile::StrictCanonGuarded);
        let (library, _, _) = reference_history_until(8);
        let admissibility =
            strict_admissibility_for_mode(9, 2, &library, AdmissibilityMode::DesktopClaimShadow);
        let accepted_candidate = step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.candidate_hash == step.accepted.candidate_hash)
            .expect("accepted step-9 candidate should stay retained");
        let accepted_rank = acceptance_rank(step.objective_bar, accepted_candidate)
            .expect("accepted step-9 candidate should clear the bar");
        let structural_acceptance =
            super::select_acceptance(step.objective_bar, &step.retained_candidates)
                .expect("raw structural acceptance should still select a bar clearer");
        let target_candidate = step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.candidate_hash == guarded_step.accepted.candidate_hash)
            .expect("guarded step-9 candidate should stay retained");
        let tied_candidates = step
            .retained_candidates
            .iter()
            .filter_map(|candidate| {
                acceptance_rank(step.objective_bar, candidate).map(|rank| (candidate, rank))
            })
            .filter(|(_, rank)| crate::branch_bound::same_primary_rank_tier(rank, &accepted_rank))
            .collect::<Vec<_>>();
        let exact_bundle_matches = tied_candidates
            .iter()
            .filter(|(candidate, _)| {
                super::claim_step_nine_matches_axiomatic_bundle(
                    &candidate.telescope,
                    &library,
                    admissibility.historical_anchor_ref,
                )
            })
            .map(|(candidate, _)| candidate.candidate_hash.clone())
            .collect::<Vec<_>>();

        assert!(
            tied_candidates.len() > 1,
            "the guarded step-9 prefix should still expose a same-primary acceptance fork"
        );
        assert_eq!(
            exact_bundle_matches,
            vec![guarded_step.accepted.candidate_hash.clone()],
            "exactly one tied step-9 survivor should match the guarded historical-anchor axiomatic bundle"
        );
        assert_ne!(
            structural_acceptance.accepted.candidate_hash, target_candidate.candidate_hash,
            "the raw structural tie-break should still miss the guarded step-9 axiomatic bundle"
        );
        assert!(
            accepted_candidate.bit_kappa > structural_acceptance.accepted.bit_kappa,
            "the repaired step-9 selector should now override the cheaper same-primary tie in favor of the guarded axiomatic bundle"
        );
        assert_eq!(
            step.accepted.candidate_hash, target_candidate.candidate_hash,
            "live claim step-9 acceptance should now prefer the guarded historical-anchor axiomatic bundle"
        );
    }

    #[test]
    fn claim_step_eleven_same_primary_fork_now_collapses_to_one_step_twelve_34_6_continuation() {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            10,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 10 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (library, history, _) = history_from_prefix(&claim_prefix);
        let target = Telescope::reference(11);
        let observed_step_twelve = super::search_bootstrap_prefix_for_profile_with_runtime(
            12,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim step 12 should build")
        .into_iter()
        .last()
        .expect("claim step 12 should exist");
        let step = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim step 11 should build")
        .into_iter()
        .last()
        .expect("claim step 11 should exist");
        let target_candidate = step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.telescope == target)
            .expect("guarded step-11 completion should stay retained");

        let structural_acceptance =
            super::select_acceptance(step.objective_bar, &step.retained_candidates)
                .expect("raw structural acceptance should still select a bar clearer");
        let structural_accepted_candidate = step
            .retained_candidates
            .iter()
            .find(|candidate| {
                candidate.candidate_hash == structural_acceptance.accepted.candidate_hash
            })
            .expect("raw structural winner should still be retained");
        let structural_accept_rank =
            acceptance_rank(step.objective_bar, structural_accepted_candidate)
                .expect("raw structural winner should still clear the bar");
        let tied_candidates = step
            .retained_candidates
            .iter()
            .filter_map(|candidate| {
                acceptance_rank(step.objective_bar, candidate).map(|rank| (candidate, rank))
            })
            .filter(|(_, rank)| {
                crate::branch_bound::same_primary_rank_tier(rank, &structural_accept_rank)
            })
            .map(|(candidate, _)| candidate)
            .collect::<Vec<_>>();
        assert!(
            tied_candidates.len() > 1,
            "the divergent step-11 surface should still expose a same-primary acceptance fork"
        );

        let continuation_outcomes = tied_candidates
            .iter()
            .filter_map(|candidate| {
                let mut next_history = history.clone();
                next_history.push(DiscoveryRecord::new(
                    11,
                    u32::from(candidate.nu),
                    u32::from(candidate.clause_kappa),
                ));
                let mut next_library = library.clone();
                next_library.push(LibraryEntry::from_telescope(&candidate.telescope, &library));
                let mut progress_observer = None;
                search_next_step_internal(
                    12,
                    2,
                    &next_library,
                    &next_history,
                    AdmissibilityMode::DesktopClaimShadow,
                    crate::diversify::FrontierRuntimeLimits::unlimited(),
                    None,
                    &mut progress_observer,
                    false,
                )
                .ok()
                .map(|continuation| {
                    (
                        candidate.candidate_hash.clone(),
                        continuation.accepted.candidate_hash,
                        continuation.accepted.nu,
                        continuation.accepted.clause_kappa,
                    )
                })
            })
            .collect::<Vec<_>>();
        let continued_outcomes = continuation_outcomes
            .iter()
            .map(|(_, accepted_hash, nu, clause_kappa)| (accepted_hash.clone(), *nu, *clause_kappa))
            .collect::<std::collections::BTreeSet<_>>();
        assert_eq!(
            continuation_outcomes.len(),
            tied_candidates.len(),
            "every tied step-11 survivor should still keep step 12 alive"
        );
        assert_ne!(
            structural_acceptance.accepted.candidate_hash, target_candidate.candidate_hash,
            "the raw structural tie-break should still miss the guarded step-11 survivor"
        );
        assert_eq!(
            step.accepted.candidate_hash, target_candidate.candidate_hash,
            "live claim step-11 acceptance should now prefer the guarded same-primary survivor"
        );
        assert_eq!(
            continued_outcomes,
            std::collections::BTreeSet::from([(
                observed_step_twelve.accepted.candidate_hash,
                observed_step_twelve.accepted.nu,
                observed_step_twelve.accepted.clause_kappa,
            )]),
            "same-primary step-11 survivors should now collapse onto one observed step-12 34/6 continuation"
        );
    }

    #[test]
    fn claim_step_eleven_acceptance_prefers_guarded_leaner_same_primary_shell() {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            10,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 10 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (_, _, _) = history_from_prefix(&claim_prefix);
        let target = Telescope::reference(11);
        let step = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim step 11 should build")
        .into_iter()
        .last()
        .expect("claim step 11 should exist");

        let structural_acceptance =
            super::select_acceptance(step.objective_bar, &step.retained_candidates)
                .expect("raw structural acceptance should still select a bar clearer");
        let structural_accepted_candidate = step
            .retained_candidates
            .iter()
            .find(|candidate| {
                candidate.candidate_hash == structural_acceptance.accepted.candidate_hash
            })
            .expect("raw structural winner should still be retained");
        let structural_accept_rank =
            acceptance_rank(step.objective_bar, structural_accepted_candidate)
                .expect("raw structural winner should still clear the bar");
        let target_candidate = step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.telescope == target)
            .expect("guarded step-11 completion should stay retained");
        let target_rank = acceptance_rank(step.objective_bar, target_candidate)
            .expect("guarded step-11 completion should still clear the bar");

        assert_eq!(structural_accept_rank.overshoot, target_rank.overshoot);
        assert_eq!(
            structural_accept_rank.clause_kappa,
            target_rank.clause_kappa
        );
        assert!(
            structural_accepted_candidate.signals.former_score
                > target_candidate.signals.former_score,
            "the raw structural winner should still be the richer former shell"
        );
        assert!(
            structural_accepted_candidate
                .signals
                .dependent_motive_density
                > target_candidate.signals.dependent_motive_density,
            "the raw structural winner should still carry the denser dependent motive shell"
        );
        assert!(
            structural_accepted_candidate.signals.generic_binder_count
                > target_candidate.signals.generic_binder_count,
            "the raw structural winner should still be the heavier binder shell"
        );
        assert!(
            target_rank.bit_kappa < structural_accept_rank.bit_kappa,
            "the guarded step-11 survivor should still be the lower-bit-cost same-primary tie"
        );
        assert_eq!(
            step.accepted.candidate_hash, target_candidate.candidate_hash,
            "live claim acceptance should now prefer the lower-bit-cost guarded step-11 survivor"
        );
    }

    #[test]
    fn claim_step_eleven_keeps_the_guarded_completion_in_the_retained_pool() {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            10,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 10 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (library, history, nu_history) = history_from_prefix(&claim_prefix);
        let target = Telescope::reference(11);
        let prefix = Telescope::new(target.clauses[..4].to_vec());
        let target_clause = target.clauses[4].clone();
        let admissibility =
            strict_admissibility_for_mode(11, 2, &library, AdmissibilityMode::DesktopClaimShadow);
        let context = EnumerationContext::from_admissibility(&library, admissibility);
        let clause_catalog = build_clause_catalog(context, 5);
        let signature = PrefixSignature::new(11, &library, &prefix);
        let mut cache = PrefixLegalityCache::default();

        assert!(cache.insert_root(
            signature.clone(),
            5,
            &library,
            &prefix,
            admissibility,
            LateFamilySurface::ClaimGeneric
        ));

        let terminal_clauses = super::terminal_prefix_clause_candidates(
            11,
            &library,
            admissibility,
            &signature,
            clause_catalog.clauses_at(4),
            Some(clause_catalog.terminal_connectivity_facts_at(4)),
            clause_catalog.terminal_nu_facts_at(4),
            &mut cache,
            None,
        );
        let target_clause_present = match &terminal_clauses {
            super::TerminalPrefixClauseCandidates::General(clauses)
            | super::TerminalPrefixClauseCandidates::ClaimAdmittedOpenBand(clauses) => clauses
                .iter()
                .any(|candidate| candidate.clause == &target_clause),
        };
        let summary = super::compute_terminal_prefix_completion_summary_from_candidates(
            11,
            &library,
            admissibility,
            compute_bar(2, 11, &history).bar,
            &nu_history,
            &signature,
            &prefix,
            super::TerminalPrefixSummaryPayload::Full,
            terminal_clauses,
            None,
            &mut cache,
            None,
            None,
        );
        let target_completion = summary
            .evaluations
            .as_ref()
            .expect("full summary should keep evaluations")
            .iter()
            .find_map(|evaluation| match evaluation {
                TerminalPrefixClauseEvaluation::Admitted { completion, .. }
                    if completion.telescope == target =>
                {
                    Some((completion.exact_nu, completion.bit_kappa_used))
                }
                _ => None,
            });
        let target_completion_present = summary
            .evaluations
            .as_ref()
            .expect("full summary should keep evaluations")
            .iter()
            .any(|evaluation| {
                matches!(
                    evaluation,
                    TerminalPrefixClauseEvaluation::Admitted { completion, .. }
                        if completion.telescope == target
                )
            });
        let step = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim step 11 should build")
        .into_iter()
        .last()
        .expect("claim step 11 should exist");
        let retained_target = step
            .retained_candidates
            .iter()
            .any(|candidate| candidate.telescope == target);
        let accepted_rank = acceptance_rank(step.objective_bar, &step.accepted)
            .expect("accepted step-11 candidate should clear the bar");
        let compact_summary = super::compute_terminal_prefix_completion_summary_from_candidates(
            11,
            &library,
            admissibility,
            compute_bar(2, 11, &history).bar,
            &nu_history,
            &signature,
            &prefix,
            super::TerminalPrefixSummaryPayload::Compact,
            super::terminal_prefix_clause_candidates(
                11,
                &library,
                admissibility,
                &signature,
                clause_catalog.clauses_at(4),
                Some(clause_catalog.terminal_connectivity_facts_at(4)),
                clause_catalog.terminal_nu_facts_at(4),
                &mut cache,
                None,
            ),
            Some(&accepted_rank),
            &mut cache,
            None,
            None,
        );
        let target_compact_survivor = match &compact_summary.compact_survivor_sketch {
            Some(sketch) => sketch.survivors.iter().find_map(|survivor| {
                clause_catalog
                    .clauses_at(4)
                    .get(survivor.clause_index)
                    .is_some_and(|clause| clause == &target_clause)
                    .then_some((survivor.exact_nu, survivor.bit_kappa_used))
            }),
            None => None,
        };

        assert!(
            target_clause_present,
            "the guarded step-11 closing clause should stay visible in the claim terminal clause catalog"
        );
        assert_eq!(
            target_completion,
            Some((26, 79)),
            "the guarded step-11 completion should stay exact-admitted on the divergent claim history"
        );
        assert!(
            target_completion_present,
            "the guarded step-11 completion should stay visible in the full remaining-one summary"
        );
        assert_eq!(
            target_compact_survivor,
            Some((26, 79)),
            "the guarded step-11 completion should stay visible in the compact survivor sketch even with an incumbent"
        );
        assert!(
            retained_target,
            "the guarded step-11 completion should survive claim incumbent pruning into the retained candidate pool"
        );
    }

