    #[test]
    fn claim_step_twelve_guarded_curvature_shell_survives_screening_and_wins_same_primary_selection()
     {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 11 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (library, history, nu_history) = history_from_prefix(&claim_prefix);
        let admissibility =
            strict_admissibility_for_mode(12, 2, &library, AdmissibilityMode::DesktopClaimShadow);
        let structural_step = search_next_step_internal(
            12,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut None,
            false,
        )
        .expect("claim step 12 should build");
        let mut progress_observer = None;
        let live_step = super::search_next_step(
            12,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut progress_observer,
        )
        .expect("live claim step 12 should build");
        let target = Telescope::reference(12);
        let preterminal_prefix = Telescope::new(target.clauses[..4].to_vec());
        let preterminal_clause = target.clauses[4].clone();
        let prefix = Telescope::new(target.clauses[..5].to_vec());
        let target_clause = target.clauses[5].clone();
        let objective_bar = compute_bar(2, 12, &history).bar;
        let context = EnumerationContext::from_admissibility(&library, admissibility);
        let clause_catalog = build_clause_catalog(context, 6);
        let preterminal_signature = PrefixSignature::new(12, &library, &preterminal_prefix);
        let signature = PrefixSignature::new(12, &library, &prefix);
        let mut cache = PrefixLegalityCache::default();
        assert!(cache.insert_root(
            preterminal_signature.clone(),
            6,
            &library,
            &preterminal_prefix,
            admissibility,
            LateFamilySurface::ClaimGeneric
        ));
        let preterminal_work_item = create_online_prefix_work_item(
            6,
            preterminal_prefix.clone(),
            preterminal_signature.clone(),
            &library,
            admissibility,
            &clause_catalog,
            &mut cache,
        );
        let preterminal_clause_present = preterminal_work_item
            .next_clauses(&clause_catalog)
            .iter()
            .any(|clause| *clause == preterminal_clause);
        assert!(cache.insert_child(
            &preterminal_signature,
            signature.clone(),
            &library,
            &preterminal_clause,
            admissibility,
        ));
        assert!(cache.insert_root(
            signature.clone(),
            6,
            &library,
            &prefix,
            admissibility,
            LateFamilySurface::ClaimGeneric
        ));
        let terminal_clauses = super::terminal_prefix_clause_candidates(
            12,
            &library,
            admissibility,
            &signature,
            clause_catalog.clauses_at(5),
            Some(clause_catalog.terminal_connectivity_facts_at(5)),
            clause_catalog.terminal_nu_facts_at(5),
            &mut cache,
            None,
        );
        let target_clause_present = match &terminal_clauses {
            super::TerminalPrefixClauseCandidates::General(clauses)
            | super::TerminalPrefixClauseCandidates::ClaimAdmittedOpenBand(clauses) => clauses
                .iter()
                .any(|candidate| candidate.clause == &target_clause),
        };
        let summary = super::compute_terminal_prefix_completion_summary_from_candidates(
            12,
            &library,
            admissibility,
            compute_bar(2, 12, &history).bar,
            &nu_history,
            &signature,
            &prefix,
            super::TerminalPrefixSummaryPayload::Full,
            terminal_clauses,
            None,
            &mut cache,
            None,
            None,
        );
        let target_completion = summary
            .evaluations
            .as_ref()
            .expect("full summary should keep evaluations")
            .iter()
            .find_map(|evaluation| match evaluation {
                TerminalPrefixClauseEvaluation::Admitted { completion, .. }
                    if completion.telescope == target =>
                {
                    Some((completion.exact_nu, completion.bit_kappa_used))
                }
                _ => None,
            });
        let structural_acceptance = super::select_acceptance(
            structural_step.objective_bar,
            &structural_step.retained_candidates,
        )
        .expect("raw structural acceptance should still select a bar clearer");
        let target_candidate = structural_step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.telescope == target)
            .expect("guarded step-12 candidate should stay retained");
        let accepted_rank =
            acceptance_rank(structural_step.objective_bar, &structural_step.accepted)
                .expect("accepted structural step-12 candidate should clear the bar");
        let target_work_item = create_online_prefix_work_item(
            6,
            prefix.clone(),
            signature.clone(),
            &library,
            admissibility,
            &clause_catalog,
            &mut cache,
        );
        let mut probe_discovery = RealisticShadowDiscovery::default();
        probe_discovery.prefix_legality_cache = cache.clone();
        probe_discovery.terminal_rank_incumbent = Some(accepted_rank.clone());
        let (target_screen_decision, _) = screen_prefix_for_frontier(
            12,
            &library,
            admissibility,
            objective_bar,
            &nu_history,
            &clause_catalog,
            &target_work_item,
            &mut probe_discovery,
        );
        let compact_summary = super::compute_terminal_prefix_completion_summary_from_candidates(
            12,
            &library,
            admissibility,
            compute_bar(2, 12, &history).bar,
            &nu_history,
            &signature,
            &prefix,
            super::TerminalPrefixSummaryPayload::Compact,
            super::terminal_prefix_clause_candidates(
                12,
                &library,
                admissibility,
                &signature,
                clause_catalog.clauses_at(5),
                Some(clause_catalog.terminal_connectivity_facts_at(5)),
                clause_catalog.terminal_nu_facts_at(5),
                &mut cache,
                None,
            ),
            Some(&accepted_rank),
            &mut cache,
            None,
            None,
        );
        let target_compact_survivor = match &compact_summary.compact_survivor_sketch {
            Some(sketch) => sketch.survivors.iter().find_map(|survivor| {
                clause_catalog
                    .clauses_at(5)
                    .get(survivor.clause_index)
                    .is_some_and(|clause| clause == &target_clause)
                    .then_some((survivor.exact_nu, survivor.bit_kappa_used))
            }),
            None => None,
        };
        let target_evaluation = evaluate_candidate(&library, &history, target.clone())
            .expect("target step-12 evaluates");
        let target_rank = acceptance_rank(structural_step.objective_bar, target_candidate)
            .expect("guarded step-12 candidate should still clear the bar");
        let target_minimality = analyze_semantic_minimality(
            12,
            structural_step.objective_bar,
            admissibility,
            &target,
            &library,
            &nu_history,
        );
        let guarded_step_twelve =
            profile_step_from_reference_prefix(12, SearchProfile::StrictCanonGuarded);
        let leaner_same_primary_candidate = structural_step
            .retained_candidates
            .iter()
            .find(|candidate| {
                candidate.telescope.clauses.len() == target.clauses.len()
                    && candidate.telescope.clauses[..4] == target.clauses[..4]
                    && candidate.telescope.clauses[5] == target.clauses[5]
                    && matches!(
                        candidate.telescope.clauses[4].expr,
                        Expr::Lam(ref body) if matches!(body.as_ref(), Expr::Var(1))
                    )
            })
            .expect("the leaner lam-var same-primary step-12 shell should stay retained");
        let leaner_same_primary_rank =
            acceptance_rank(structural_step.objective_bar, leaner_same_primary_candidate)
                .expect("the leaner same-primary step-12 shell should still clear the bar");
        let richer_intro_former_candidate = structural_step
            .retained_candidates
            .iter()
            .find(|candidate| {
                candidate.telescope.clauses.len() == target.clauses.len()
                    && candidate.telescope.clauses[2..] == target.clauses[2..]
                    && matches!(
                        candidate.telescope.clauses[1].expr,
                        Expr::Lam(ref body)
                            if matches!(body.as_ref(), Expr::Pi(_, _))
                    )
            })
            .expect("the richer step-12 double-former same-primary sibling should stay retained");
        let richer_intro_former_rank =
            acceptance_rank(structural_step.objective_bar, richer_intro_former_candidate)
                .expect("the richer same-primary step-12 sibling should still clear the bar");
        assert!(
            target_minimality.is_minimal(),
            "claim open-band minimality should no longer prune the guarded step-12 shell using a worse-ranked detachable subbundle"
        );
        assert!(
            preterminal_clause_present,
            "the guarded step-12 fourth-clause prefix should still expose the guarded fifth clause"
        );
        assert_eq!(
            target_screen_decision,
            ExactPartialPrefixBoundDecision::CanClearBar,
            "the guarded step-12 remaining-one prefix should now survive claim exact screening"
        );
        assert!(target_clause_present);
        assert_eq!(target_completion, Some((34, 121)));
        assert_eq!(
            target_compact_survivor,
            Some((34, 121)),
            "the guarded step-12 completion should stay visible in the compact survivor sketch"
        );
        assert_eq!(target_evaluation.nu, 34);
        assert_eq!(target_evaluation.clause_kappa, 6);
        assert!(
            super::claim_introduction_application_count(&target_candidate.telescope)
                > super::claim_introduction_application_count(
                    &richer_intro_former_candidate.telescope
                ),
            "the guarded curvature shell should still preserve more introduction-level application structure than the richer double-former sibling"
        );
        assert!(
            super::claim_introduction_former_count(&target_candidate.telescope)
                > super::claim_introduction_former_count(&leaner_same_primary_candidate.telescope),
            "the guarded curvature shell should still carry a richer introduction-level former shell than the new leaner same-primary sibling"
        );
        assert_eq!(
            super::compare_claim_step_twelve_same_primary_survivors(
                target_candidate,
                &target_rank,
                leaner_same_primary_candidate,
                &leaner_same_primary_rank,
            ),
            std::cmp::Ordering::Less,
            "the step-12 same-primary selector should prefer the guarded curvature shell over the leaner lam-var sibling"
        );
        assert_eq!(
            super::compare_claim_step_twelve_same_primary_survivors(
                target_candidate,
                &target_rank,
                richer_intro_former_candidate,
                &richer_intro_former_rank,
            ),
            std::cmp::Ordering::Less,
            "the step-12 same-primary selector should still prefer the guarded curvature shell over the richer double-former sibling"
        );
        assert_ne!(
            structural_acceptance.accepted.candidate_hash, target_candidate.candidate_hash,
            "the raw structural tie-break should still miss the guarded step-12 curvature shell"
        );
        assert_eq!(
            live_step.accepted.candidate_hash, guarded_step_twelve.accepted.candidate_hash,
            "live claim step-12 acceptance should now prefer the guarded curvature shell inside the same-primary 34/6 tier"
        );
        assert_eq!(live_step.accepted.nu, guarded_step_twelve.accepted.nu);
        assert_eq!(
            live_step.accepted.clause_kappa,
            guarded_step_twelve.accepted.clause_kappa
        );
        assert!(
            structural_step
                .retained_candidates
                .iter()
                .any(|candidate| candidate.candidate_hash == target_evaluation.candidate_hash),
            "the guarded step-12 curvature shell should now stay in the retained pool once the cross-band bound cache stops poisoning the 6-clause continuation"
        );
    }

    #[test]
    fn claim_step_twelve_same_primary_fork_now_collapses_to_one_step_thirteen_to_fifteen_surface() {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 11 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (library, history, _) = history_from_prefix(&claim_prefix);
        let mut progress_observer = None;
        let live_step = super::search_next_step(
            12,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut progress_observer,
        )
        .expect("live claim step 12 should build");
        let accepted_candidate = live_step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.candidate_hash == live_step.accepted.candidate_hash)
            .expect("accepted step-12 candidate should stay retained");
        let accepted_rank = acceptance_rank(live_step.objective_bar, accepted_candidate)
            .expect("accepted step-12 candidate should clear the bar");
        let target = Telescope::reference(12);
        let tied_candidates = live_step
            .retained_candidates
            .iter()
            .filter_map(|candidate| {
                acceptance_rank(live_step.objective_bar, candidate).map(|rank| (candidate, rank))
            })
            .filter(|(_, rank)| crate::branch_bound::same_primary_rank_tier(rank, &accepted_rank))
            .collect::<Vec<_>>();
        let target_candidate = live_step
            .retained_candidates
            .iter()
            .find(|candidate| candidate.telescope == target)
            .expect("guarded step-12 candidate should stay retained");
        assert!(
            tied_candidates.len() > 1,
            "the repaired step-12 surface should still expose a same-primary 34/6 tie set"
        );
        assert!(
            tied_candidates
                .iter()
                .any(|(candidate, _)| candidate.candidate_hash == target_candidate.candidate_hash),
            "the guarded step-12 curvature shell should stay inside the tied same-primary set"
        );

        let continue_late_path = |candidate: &crate::expand::ExpandedCandidate| {
            let mut next_history = history.clone();
            next_history.push(DiscoveryRecord::new(
                12,
                u32::from(candidate.nu),
                u32::from(candidate.clause_kappa),
            ));
            let mut next_library = library.clone();
            next_library.push(LibraryEntry::from_telescope(&candidate.telescope, &library));
            let mut late_steps = Vec::new();
            for step_index in 13..=15 {
                let mut progress_observer = None;
                let next_step = super::search_next_step(
                    step_index,
                    2,
                    &next_library,
                    &next_history,
                    AdmissibilityMode::DesktopClaimShadow,
                    crate::diversify::FrontierRuntimeLimits::unlimited(),
                    None,
                    &mut progress_observer,
                )
                .expect("late continuation should build");
                late_steps.push((
                    step_index,
                    next_step.accepted.candidate_hash.clone(),
                    next_step.accepted.nu,
                    next_step.accepted.clause_kappa,
                    next_step.demo_funnel.generated_raw_prefixes,
                ));
                next_history.push(DiscoveryRecord::new(
                    step_index,
                    u32::from(next_step.accepted.nu),
                    u32::from(next_step.accepted.clause_kappa),
                ));
                next_library.push(LibraryEntry::from_telescope(
                    &next_step.telescope,
                    &next_library,
                ));
            }
            late_steps
        };
        let observed_late_path = continue_late_path(target_candidate);
        let guarded_step_thirteen =
            profile_step_from_reference_prefix(13, SearchProfile::StrictCanonGuarded);
        assert_eq!(
            observed_late_path[0].1, guarded_step_thirteen.accepted.candidate_hash,
            "the scoped step-13 widening should keep the guarded metric shell as the accepted late-step shell"
        );
        assert_eq!(
            observed_late_path
                .iter()
                .map(|(step_index, _, nu, clause_kappa, generated)| {
                    (*step_index, *nu, *clause_kappa, *generated)
                })
                .collect::<Vec<_>>(),
            vec![(13, 46, 7, 2320), (14, 62, 9, 12027), (15, 103, 8, 4331)],
            "the repaired step-12 tie set should now collapse onto the parity-preserving widened step-13 surface while restoring the latest canonical step-15 continuation"
        );
        let alternate_candidate = tied_candidates
            .iter()
            .map(|(candidate, _)| *candidate)
            .find(|candidate| candidate.candidate_hash != target_candidate.candidate_hash)
            .expect(
                "the tied step-12 surface should still expose an alternate same-primary survivor",
            );
        assert_eq!(
            continue_late_path(alternate_candidate),
            observed_late_path,
            "the widened step-14 selector should keep an alternate same-primary step-12 survivor on the same observed step-13 to step-15 continuation"
        );
    }

    #[test]
    fn repaired_claim_step_twelve_late_path_has_scoped_step_thirteen_widening_before_proof_close() {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 11 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (mut library, mut history, _) = history_from_prefix(&claim_prefix);
        let mut progress_observer = None;
        let step_twelve = super::search_next_step(
            12,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut progress_observer,
        )
        .expect("live claim step 12 should build");
        history.push(DiscoveryRecord::new(
            12,
            u32::from(step_twelve.accepted.nu),
            u32::from(step_twelve.accepted.clause_kappa),
        ));
        library.push(LibraryEntry::from_telescope(
            &step_twelve.telescope,
            &library,
        ));

        let inspect_late_step = |step_index, library: &Library, history: &[DiscoveryRecord]| {
            let mut recorder = LiveCheckpointRecorder::default();
            let mut progress_observer: Option<&mut dyn AtomicSearchProgressObserver> =
                Some(&mut recorder);
            let step = super::search_next_step(
                step_index,
                2,
                library,
                history,
                AdmissibilityMode::DesktopClaimShadow,
                crate::diversify::FrontierRuntimeLimits::unlimited(),
                None,
                &mut progress_observer,
            )
            .expect("late continuation should build");
            let catalog_checkpoint = recorder
                .checkpoints
                .iter()
                .find(|checkpoint| {
                    checkpoint.note.as_deref() == Some("claim_regular_clause_catalog")
                })
                .expect("late claim step should emit the regular catalog checkpoint")
                .clone();
            let root_summary = recorder
                .checkpoints
                .iter()
                .find(|checkpoint| checkpoint.note.as_deref() == Some("claim_root_seeding_summary"))
                .expect("late claim step should emit the root seeding summary checkpoint")
                .clone();
            (step, catalog_checkpoint, root_summary)
        };

        let (step_thirteen, step_thirteen_catalog, step_thirteen_roots) =
            inspect_late_step(13, &library, &history);
        let step_thirteen_open = step_thirteen_roots
            .claim_step_open
            .expect("step 13 should still emit claim-open diagnostics");
        assert_eq!(step_thirteen_open.kappa_min, 7);
        assert_eq!(step_thirteen_open.kappa_max, 7);
        assert_eq!(
            step_thirteen_open.late_family_surface,
            LateFamilySurface::ClaimGeneric
        );
        assert_eq!(
            step_thirteen_open.anchor_policy,
            ClaimAnchorPolicyDiagnostics::None
        );
        assert_eq!(step_thirteen_open.claim_debt_axes.kappa_min, 7);
        assert_eq!(step_thirteen_open.claim_debt_axes.kappa_max, 7);
        assert!(step_thirteen_open.package_flags.operator_bundle);
        assert!(!step_thirteen_open.package_flags.hilbert_functional);
        assert!(!step_thirteen_open.package_flags.temporal_shell);
        assert_eq!(
            step_thirteen_catalog.raw_catalog_clause_widths,
            vec![5, 1, 3, 3, 5, 3, 2]
        );
        assert_eq!(
            step_thirteen_catalog.raw_catalog_telescope_count,
            Some(1350)
        );
        assert_eq!(step_thirteen.telescope, Telescope::reference(13));
        assert_eq!(step_thirteen.demo_funnel.generated_raw_prefixes, 2320);
        assert_eq!(
            step_thirteen.claim_root_seeding,
            Some(ClaimRootSeedingDiagnostics {
                roots_seen: 5,
                roots_rejected_by_insert_root: 0,
                roots_rejected_by_exact_screen: 0,
                roots_enqueued: 5,
            })
        );
        assert_eq!(
            step_thirteen_roots.claim_root_seeding,
            step_thirteen.claim_root_seeding
        );
        assert_eq!(step_thirteen.incremental_partial_prefix_bound_prunes, 0);
        assert_eq!(
            step_thirteen
                .exact_screen_reasons
                .partial_prefix_bar_failure,
            0
        );
        assert_eq!(
            step_thirteen
                .exact_screen_reasons
                .legality_connectivity_exact_rejection,
            576
        );
        history.push(DiscoveryRecord::new(
            13,
            u32::from(step_thirteen.accepted.nu),
            u32::from(step_thirteen.accepted.clause_kappa),
        ));
        library.push(LibraryEntry::from_telescope(
            &step_thirteen.telescope,
            &library,
        ));

        let (step_fourteen, step_fourteen_catalog, step_fourteen_roots) =
            inspect_late_step(14, &library, &history);
        let accepted_rank = acceptance_rank(step_fourteen.objective_bar, &step_fourteen.accepted)
            .expect("accepted step-14 candidate should clear the bar");
        let mut step_fourteen_same_primary = step_fourteen
            .retained_candidates
            .iter()
            .filter_map(|candidate| {
                acceptance_rank(step_fourteen.objective_bar, candidate)
                    .map(|rank| (candidate, rank))
            })
            .filter(|(_, rank)| crate::branch_bound::same_primary_rank_tier(rank, &accepted_rank))
            .collect::<Vec<_>>();
        step_fourteen_same_primary
            .sort_by(|(left, _), (right, _)| left.candidate_hash.cmp(&right.candidate_hash));
        let step_fourteen_continuations = step_fourteen_same_primary
            .iter()
            .map(|(candidate, _)| {
                let mut next_history = history.clone();
                next_history.push(DiscoveryRecord::new(
                    14,
                    u32::from(candidate.nu),
                    u32::from(candidate.clause_kappa),
                ));
                let mut next_library = library.clone();
                next_library.push(LibraryEntry::from_telescope(&candidate.telescope, &library));
                let mut progress_observer = None;
                let next_step = super::search_next_step(
                    15,
                    2,
                    &next_library,
                    &next_history,
                    AdmissibilityMode::DesktopClaimShadow,
                    crate::diversify::FrontierRuntimeLimits::unlimited(),
                    None,
                    &mut progress_observer,
                )
                .expect("step 15 continuation should build");
                (
                    candidate.candidate_hash.clone(),
                    next_step.accepted.nu,
                    next_step.accepted.clause_kappa,
                    next_step.demo_funnel.generated_raw_prefixes,
                )
            })
            .collect::<Vec<_>>();
        assert_eq!(
            step_fourteen_catalog.raw_catalog_telescope_count,
            Some(19683)
        );
        assert_eq!(step_fourteen.demo_funnel.generated_raw_prefixes, 12027);
        assert_eq!(
            step_fourteen.claim_root_seeding,
            Some(ClaimRootSeedingDiagnostics {
                roots_seen: 3,
                roots_rejected_by_insert_root: 0,
                roots_rejected_by_exact_screen: 0,
                roots_enqueued: 3,
            })
        );
        assert_eq!(
            step_fourteen_roots.claim_root_seeding,
            step_fourteen.claim_root_seeding
        );
        assert_eq!(step_fourteen.incremental_partial_prefix_bound_prunes, 1458);
        assert_eq!(
            step_fourteen
                .exact_screen_reasons
                .partial_prefix_bar_failure,
            1458
        );
        assert_eq!(step_fourteen.exact_screen_reasons.incumbent_dominance, 6551);
        assert!(
            step_fourteen.demo_bucket_stats.iter().any(|bucket| {
                bucket.stats.generated_terminal_candidates == 6579
                    && bucket.stats.exact_screened_terminal_candidates == 6579
                    && bucket.stats.pruned_terminal_candidates == 6551
                    && bucket.stats.fully_scored_terminal_candidates == 4
            }),
            "step 14 should now widen the claim catalog well before proof-close"
        );
        assert_eq!(
            step_fourteen_continuations.len(),
            4,
            "the widened step-14 claim surface should expose a same-primary continuation fork"
        );
        let accepted_step_fourteen_continuation = step_fourteen_continuations
            .iter()
            .find(|(candidate_hash, _, _, _)| {
                *candidate_hash == step_fourteen.accepted.candidate_hash
            })
            .expect("accepted step-14 continuation should still be present");
        assert_eq!(
            (
                accepted_step_fourteen_continuation.1,
                accepted_step_fourteen_continuation.2,
                accepted_step_fourteen_continuation.3,
            ),
            (103, 8, 4331),
            "live claim step-14 acceptance should now prefer the same-primary survivor that restores the latest broadened canonical step-15 continuation"
        );
        assert!(
            step_fourteen_continuations.iter().any(
                |(candidate_hash, nu, clause_kappa, generated)| {
                    *candidate_hash != step_fourteen.accepted.candidate_hash
                        && *nu == 78
                        && *clause_kappa == 9
                        && *generated == 12027
                }
            ),
            "the step-14 same-primary fork should still retain the broader 78/9 continuation as the alternate branch"
        );

        history.push(DiscoveryRecord::new(
            14,
            u32::from(step_fourteen.accepted.nu),
            u32::from(step_fourteen.accepted.clause_kappa),
        ));
        library.push(LibraryEntry::from_telescope(
            &step_fourteen.telescope,
            &library,
        ));

        let (step_fifteen, step_fifteen_catalog, step_fifteen_roots) =
            inspect_late_step(15, &library, &history);
        assert_eq!(step_fifteen_catalog.raw_catalog_telescope_count, Some(6561));
        assert_eq!(step_fifteen.demo_funnel.generated_raw_prefixes, 4331);
        assert_eq!(
            step_fifteen.claim_root_seeding,
            Some(ClaimRootSeedingDiagnostics {
                roots_seen: 3,
                roots_rejected_by_insert_root: 0,
                roots_rejected_by_exact_screen: 0,
                roots_enqueued: 3,
            })
        );
        assert_eq!(
            step_fifteen_roots.claim_root_seeding,
            step_fifteen.claim_root_seeding
        );
        assert_eq!(step_fifteen.incremental_partial_prefix_bound_prunes, 553);
        assert_eq!(
            step_fifteen.exact_screen_reasons.partial_prefix_bar_failure,
            553
        );
        assert_eq!(step_fifteen.exact_screen_reasons.incumbent_dominance, 3);
        assert!(
            step_fifteen.demo_bucket_stats.iter().any(|bucket| {
                bucket.stats.generated_terminal_candidates == 0
                    && bucket.stats.admissible_terminal_candidates == 0
                    && bucket.stats.exact_screened_terminal_candidates == 0
                    && bucket.stats.pruned_terminal_candidates == 3
                    && bucket.stats.fully_scored_terminal_candidates == 1
                    && bucket.stats.best_overshoot == Some(Rational::new(115657, 21112))
            }),
            "step 15 should keep the isolated anchor-11 exact-argument pocket fenced as one non-winning fully scored terminal while leaving only three residual single-bucket incumbent prunes"
        );
        assert!(
            step_fifteen.demo_bucket_stats.iter().any(|bucket| {
                bucket.stats.generated_terminal_candidates == 3132
                    && bucket.stats.admissible_terminal_candidates == 522
                    && bucket.stats.exact_screened_terminal_candidates == 522
                    && bucket.stats.pruned_terminal_candidates == 0
            }),
            "step 15 should now carry the temporal small-cluster through exact screening while keeping the canonical continuation"
        );
    }

