    #[test]
    fn current_claim_step_fifteen_residual_single_bucket_incumbent_families_still_hide_two_unsafe_lifted_terminals()
     {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let canonical_rank = super::acceptance_rank_for_telescope(
            surface.objective_bar,
            &Telescope::reference(15),
            103,
            u16::try_from(pen_core::encode::telescope_bit_cost(&Telescope::reference(
                15,
            )))
            .expect("bit cost exceeded u16"),
            8,
        )
        .expect("reference step-15 telescope should clear the bar");
        let captures = {
            super::start_incumbent_pruned_terminal_group_capture();
            let _ = profile_step_from_reference_prefix(15, SearchProfile::DesktopClaimShadow);
            super::finish_incumbent_pruned_terminal_group_capture()
        };
        let reference_terminal = Telescope::reference(15)
            .clauses
            .last()
            .cloned()
            .expect("reference step 15 should have a terminal clause");
        let next_lift_terminal = ClauseRec::new(
            ClauseRole::Formation,
            Expr::Pi(
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(Expr::Next(
                    Box::new(Expr::Var(1)),
                )))))),
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(Expr::Var(1)))))),
            ),
        );
        let eventual_lift_terminal = ClauseRec::new(
            ClauseRole::Formation,
            Expr::Pi(
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(
                    Expr::Eventually(Box::new(Expr::Var(1))),
                ))))),
                Box::new(Expr::Next(Box::new(Expr::Eventually(Box::new(Expr::Var(
                    1,
                )))))),
            ),
        );
        let mut profiles = BTreeMap::new();

        let mut prefix_legality_cache = PrefixLegalityCache::default();
        for capture in captures {
            let label = current_claim_step_fifteen_proof_close_incumbent_family_label(
                &capture.prefix_telescope,
            );

            let signature = PrefixSignature::new(15, &surface.library, &capture.prefix_telescope);
            let work_item = create_online_prefix_work_item(
                8,
                capture.prefix_telescope.clone(),
                signature,
                &surface.library,
                surface.admissibility,
                &surface.clause_catalog,
                &mut prefix_legality_cache,
            );
            let connectivity_summary =
                ConnectivitySummary::from_telescope(&surface.library, &capture.prefix_telescope);
            let mut terminal_profiles = BTreeMap::new();
            for clause in work_item.next_clauses(&surface.clause_catalog) {
                let clause_label = if *clause == reference_terminal {
                    "reference"
                } else if *clause == next_lift_terminal {
                    "next_lift"
                } else if *clause == eventual_lift_terminal {
                    "eventual_lift"
                } else {
                    "other"
                };
                let decision =
                    connectivity_summary.terminal_decision(&surface.library, clause, true);
                let mut telescope = work_item.prefix_telescope.clone();
                telescope.clauses.push(clause.clone());
                let admissibility_decision = assess_strict_admissibility(
                    surface.step_index,
                    &surface.library,
                    &telescope,
                    surface.admissibility,
                );
                let accept_rank = if admissibility_decision.is_admitted() {
                    let exact_nu = u16::try_from(
                        structural_nu(&telescope, &surface.library, &surface.nu_history).total,
                    )
                    .expect("nu exceeded u16");
                    let bit_kappa_used =
                        u16::try_from(pen_core::encode::telescope_bit_cost(&telescope))
                            .expect("bit cost exceeded u16");
                    let clause_kappa_used =
                        u16::try_from(telescope.kappa()).expect("kappa exceeded u16");
                    super::acceptance_rank_for_telescope(
                        surface.objective_bar,
                        &telescope,
                        exact_nu,
                        bit_kappa_used,
                        clause_kappa_used,
                    )
                    .map(|rank| {
                        (
                            exact_nu,
                            bit_kappa_used,
                            super::better_rank(&rank, &canonical_rank),
                            rank.overshoot,
                        )
                    })
                } else {
                    None
                };
                terminal_profiles.insert(
                    clause_label.to_string(),
                    (decision, admissibility_decision.is_admitted(), accept_rank),
                );
            }
            profiles.insert(label, terminal_profiles);
        }

        assert_eq!(
            profiles,
            [
                (
                    "clause-0 claim_flat_domain".to_string(),
                    [
                        (
                            "eventual_lift".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((89_u16, 254_u16, true, Rational::new(78711, 21112))),
                            ),
                        ),
                        (
                            "next_lift".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((89_u16, 254_u16, true, Rational::new(78711, 21112))),
                            ),
                        ),
                        (
                            "reference".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((103_u16, 236_u16, false, Rational::new(115657, 21112))),
                            ),
                        ),
                    ]
                    .into_iter()
                    .collect(),
                ),
                (
                    "clause-2 claim_flat_domain plus anchor-11 exact-argument".to_string(),
                    [
                        (
                            "eventual_lift".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((89_u16, 254_u16, true, Rational::new(78711, 21112))),
                            ),
                        ),
                        (
                            "next_lift".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((89_u16, 254_u16, true, Rational::new(78711, 21112))),
                            ),
                        ),
                        (
                            "reference".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((103_u16, 236_u16, false, Rational::new(115657, 21112))),
                            ),
                        ),
                    ]
                    .into_iter()
                    .collect(),
                ),
                (
                    "clause-5 claim_flat_codomain".to_string(),
                    [
                        (
                            "eventual_lift".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((89_u16, 254_u16, true, Rational::new(78711, 21112))),
                            ),
                        ),
                        (
                            "next_lift".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((89_u16, 254_u16, true, Rational::new(78711, 21112))),
                            ),
                        ),
                        (
                            "reference".to_string(),
                            (
                                ConnectivityTerminalDecision::KeepWithoutFallback,
                                true,
                                Some((103_u16, 236_u16, false, Rational::new(115657, 21112))),
                            ),
                        ),
                    ]
                    .into_iter()
                    .collect(),
                ),
            ]
            .into_iter()
            .collect(),
            "each residual single-bucket family should still sit beside the same raw three-terminal shell: one same-primary 103/8 reference terminal and two unsafe stronger-than-canonical 89/8 lifts, so the next repair cannot blindly reland those families through broader same-primary retention"
        );
    }

    #[test]
    fn current_claim_step_fifteen_residual_single_bucket_incumbent_families_only_keep_reference_terminals_live()
     {
        let surface = current_claim_step_fifteen_pruned_terminal_surface(usize::MAX);
        let captures = {
            super::start_incumbent_pruned_terminal_group_capture();
            let _ = profile_step_from_reference_prefix(15, SearchProfile::DesktopClaimShadow);
            super::finish_incumbent_pruned_terminal_group_capture()
        };
        let reference_terminal = Telescope::reference(15)
            .clauses
            .last()
            .cloned()
            .expect("reference step 15 should have a terminal clause");
        let next_lift_terminal = ClauseRec::new(
            ClauseRole::Formation,
            Expr::Pi(
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(Expr::Next(
                    Box::new(Expr::Var(1)),
                )))))),
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(Expr::Var(1)))))),
            ),
        );
        let eventual_lift_terminal = ClauseRec::new(
            ClauseRole::Formation,
            Expr::Pi(
                Box::new(Expr::Next(Box::new(Expr::Next(Box::new(
                    Expr::Eventually(Box::new(Expr::Var(1))),
                ))))),
                Box::new(Expr::Next(Box::new(Expr::Eventually(Box::new(Expr::Var(
                    1,
                )))))),
            ),
        );
        let mut live_terminal_profiles = BTreeMap::new();

        for capture in captures {
            let label = current_claim_step_fifteen_proof_close_incumbent_family_label(
                &capture.prefix_telescope,
            );
            let mut terminal_profiles = BTreeMap::new();

            for (terminal_label, terminal_clause) in [
                ("reference", reference_terminal.clone()),
                ("next_lift", next_lift_terminal.clone()),
                ("eventual_lift", eventual_lift_terminal.clone()),
            ] {
                let mut telescope = capture.prefix_telescope.clone();
                telescope.clauses.push(terminal_clause);

                let witness = analyze_connectivity(&surface.library, &telescope);
                let reanchor =
                    HistoricalReanchorSummary::from_telescope(&surface.library, &telescope);
                terminal_profiles.insert(
                    terminal_label.to_string(),
                    (
                        witness.connected,
                        witness.historical_reanchor,
                        reanchor.allows_historical_reanchor(),
                        passes_connectivity(&surface.library, &telescope),
                    ),
                );
            }

            live_terminal_profiles.insert(label, terminal_profiles);
        }

        assert_eq!(
            live_terminal_profiles,
            [
                (
                    "clause-0 claim_flat_domain".to_string(),
                    [
                        ("eventual_lift".to_string(), (true, false, false, false)),
                        ("next_lift".to_string(), (true, false, false, false)),
                        ("reference".to_string(), (true, true, true, true)),
                    ]
                    .into_iter()
                    .collect(),
                ),
                (
                    "clause-2 claim_flat_domain plus anchor-11 exact-argument".to_string(),
                    [
                        ("eventual_lift".to_string(), (true, false, false, false)),
                        ("next_lift".to_string(), (true, false, false, false)),
                        ("reference".to_string(), (true, true, true, true)),
                    ]
                    .into_iter()
                    .collect(),
                ),
                (
                    "clause-5 claim_flat_codomain".to_string(),
                    [
                        ("eventual_lift".to_string(), (true, false, false, false)),
                        ("next_lift".to_string(), (true, false, false, false)),
                        ("reference".to_string(), (true, true, true, true)),
                    ]
                    .into_iter()
                    .collect(),
                ),
            ]
            .into_iter()
            .collect(),
            "each residual single-bucket family should still keep only the reference terminal live on the current claim path: both stronger-than-canonical lifted terminals remain structurally connected but outside historical reanchor and therefore fenced out of live connectivity"
        );
    }

    #[test]
    fn current_claim_step_fifteen_subset_local_same_primary_relief_only_trades_single_prunes_for_non_winners()
     {
        let family_labels = [
            "clause-0 claim_flat_domain",
            "clause-2 claim_flat_domain plus anchor-11 exact-argument",
            "clause-5 claim_flat_codomain",
        ];
        let reference_terminal = Telescope::reference(15)
            .clauses
            .last()
            .cloned()
            .expect("reference step 15 should have a terminal clause");

        for mask in 1usize..(1usize << family_labels.len()) {
            let subset = family_labels
                .iter()
                .enumerate()
                .filter_map(|(index, label)| ((mask & (1 << index)) != 0).then_some(*label))
                .collect::<Vec<_>>();
            let _override =
                super::override_claim_step_fifteen_family_local_same_primary_relief(&subset);
            let step_fifteen =
                profile_step_from_reference_prefix(15, SearchProfile::DesktopClaimShadow);
            let bucket_stats = step_fifteen
                .demo_bucket_stats
                .iter()
                .map(|bucket| (bucket.bucket_label.clone(), bucket.stats.clone()))
                .collect::<BTreeMap<_, _>>();
            let accepted_rank = acceptance_rank(step_fifteen.objective_bar, &step_fifteen.accepted)
                .expect("accepted step-15 candidate should clear the bar");
            let subset_size = subset.len();
            let extra_candidates = step_fifteen
                .retained_candidates
                .iter()
                .filter(|candidate| {
                    candidate.candidate_hash != step_fifteen.accepted.candidate_hash
                })
                .collect::<Vec<_>>();

            assert_eq!(
                step_fifteen.telescope,
                Telescope::reference(15),
                "subset-local same-primary relief should keep the repaired canonical step-15 winner"
            );
            assert_eq!(
                step_fifteen.demo_funnel.generated_raw_prefixes, 4331,
                "subset-local same-primary relief on {:?} should not broaden the repaired local step-15 generated surface",
                subset
            );
            assert_eq!(
                step_fifteen.exact_screen_reasons.partial_prefix_bar_failure, 553,
                "subset-local same-primary relief on {:?} should leave the repaired partial-prefix wall unchanged",
                subset
            );
            assert_eq!(
                step_fifteen.exact_screen_reasons.incumbent_dominance,
                3 - subset_size,
                "subset-local same-primary relief on {:?} should only remove the same number of residual single-bucket incumbent prunes as the exact families it unfreezes",
                subset
            );
            assert_eq!(
                bucket_stats.get("k8:structural_generic:temporal_operator:library_backed:single"),
                Some(&DemoBucketStats {
                    generated_terminal_candidates: 0,
                    admissible_terminal_candidates: 0,
                    exact_screened_terminal_candidates: 0,
                    pruned_terminal_candidates: 3 - subset_size,
                    fully_scored_terminal_candidates: 1 + subset_size,
                    best_overshoot: Some(Rational::new(115657, 21112)),
                }),
                "subset-local same-primary relief on {:?} should only trade residual single-bucket prunes for extra fully scored non-winning terminals in the isolated pocket",
                subset
            );
            assert_eq!(
                bucket_stats
                    .get("k8:structural_generic:temporal_operator:library_backed:small_cluster"),
                Some(&DemoBucketStats {
                    generated_terminal_candidates: 3132,
                    admissible_terminal_candidates: 522,
                    exact_screened_terminal_candidates: 522,
                    pruned_terminal_candidates: 0,
                    fully_scored_terminal_candidates: 0,
                    best_overshoot: None,
                }),
                "subset-local same-primary relief on {:?} should leave the cleared temporal small-cluster unchanged",
                subset
            );
            assert_eq!(
                extra_candidates.len(),
                subset_size,
                "subset-local same-primary relief on {:?} should add exactly one extra fully scored non-winning candidate per unfenced residual family",
                subset
            );
            let observed_labels = extra_candidates
                .iter()
                .map(|candidate| {
                    let rank = acceptance_rank(step_fifteen.objective_bar, candidate)
                        .expect("retained extra candidate should clear the bar");
                    assert!(
                        crate::branch_bound::same_primary_rank_tier(&rank, &accepted_rank),
                        "subset-local same-primary relief on {:?} should only unfence same-primary non-winning candidates",
                        subset
                    );
                    assert!(
                        !super::better_rank(&rank, &accepted_rank),
                        "subset-local same-primary relief on {:?} should not admit a stronger-than-canonical winner",
                        subset
                    );
                    assert_eq!(
                        rank.bit_kappa, 236,
                        "subset-local same-primary relief on {:?} should only unfence the 236-bit reference-terminal profile",
                        subset
                    );
                    assert_eq!(
                        rank.overshoot,
                        Rational::new(115657, 21112),
                        "subset-local same-primary relief on {:?} should keep the exact isolated single-pocket overshoot",
                        subset
                    );
                    assert_eq!(
                        candidate
                            .telescope
                            .clauses
                            .last()
                            .expect("retained candidate should have a terminal clause"),
                        &reference_terminal,
                        "subset-local same-primary relief on {:?} should only unfence reference-terminal completions",
                        subset
                    );
                    current_claim_step_fifteen_proof_close_incumbent_family_label(&Telescope::new(
                        candidate.telescope.clauses[..7].to_vec(),
                    ))
                })
                .collect::<BTreeSet<_>>();
            assert_eq!(
                observed_labels,
                subset
                    .iter()
                    .map(|label| (*label).to_string())
                    .collect::<BTreeSet<_>>(),
                "subset-local same-primary relief on {:?} should only unfence reference-terminal candidates from the selected residual families",
                subset
            );
        }
    }

    #[test]
    fn current_claim_step_fifteen_exact_family_same_primary_relief_still_unfences_the_isolated_single_pocket()
     {
        let _override = super::override_claim_step_fifteen_family_local_same_primary_relief(&[
            "clause-0 claim_flat_domain",
            "clause-2 claim_flat_domain plus anchor-11 exact-argument",
            "clause-5 claim_flat_codomain",
        ]);
        let step_fifteen =
            profile_step_from_reference_prefix(15, SearchProfile::DesktopClaimShadow);
        let bucket_stats = step_fifteen
            .demo_bucket_stats
            .iter()
            .map(|bucket| (bucket.bucket_label.clone(), bucket.stats.clone()))
            .collect::<BTreeMap<_, _>>();

        assert_eq!(step_fifteen.telescope, Telescope::reference(15));
        assert_eq!(step_fifteen.demo_funnel.generated_raw_prefixes, 4331);
        assert_eq!(
            step_fifteen.exact_screen_reasons.partial_prefix_bar_failure, 553,
            "family-local same-primary relief should now still collapse the remaining incumbent pressure only by widening the repaired local surface to 4331 and keeping the partial-prefix wall at 553"
        );
        assert_eq!(
            step_fifteen.exact_screen_reasons.incumbent_dominance, 0,
            "granting same-primary relief to only the three residual families should still collapse the last incumbent-dominance prunes"
        );
        assert_eq!(
            bucket_stats.get("k8:structural_generic:temporal_operator:library_backed:single"),
            Some(&DemoBucketStats {
                generated_terminal_candidates: 0,
                admissible_terminal_candidates: 0,
                exact_screened_terminal_candidates: 0,
                pruned_terminal_candidates: 0,
                fully_scored_terminal_candidates: 4,
                best_overshoot: Some(Rational::new(115657, 21112)),
            }),
            "even exact-family-scoped same-primary relief still unfences the isolated single pocket from one fully scored non-winner to four, so it is not the landed repair either"
        );
        assert_eq!(
            bucket_stats
                .get("k8:structural_generic:temporal_operator:library_backed:small_cluster"),
            Some(&DemoBucketStats {
                generated_terminal_candidates: 3132,
                admissible_terminal_candidates: 522,
                exact_screened_terminal_candidates: 522,
                pruned_terminal_candidates: 0,
                fully_scored_terminal_candidates: 0,
                best_overshoot: None,
            }),
            "the exact-family relief probe should leave the cleared temporal small-cluster unchanged, so the remaining blocker is still the isolated single pocket fence"
        );
    }

    #[test]
    fn repaired_claim_step_thirteen_repaired_chain_clears_exact_screen_and_terminal_rank_pressure()
    {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 11 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (mut library, mut history, _) = history_from_prefix(&claim_prefix);
        let mut progress_observer = None;
        let step_twelve = super::search_next_step(
            12,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut progress_observer,
        )
        .expect("live claim step 12 should build");
        history.push(DiscoveryRecord::new(
            12,
            u32::from(step_twelve.accepted.nu),
            u32::from(step_twelve.accepted.clause_kappa),
        ));
        library.push(LibraryEntry::from_telescope(
            &step_twelve.telescope,
            &library,
        ));

        let mut progress_observer = None;
        let step_thirteen = super::search_next_step(
            13,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut progress_observer,
        )
        .expect("step 13 should build");
        let prefix = claim_prefix
            .into_iter()
            .chain(std::iter::once(step_twelve.telescope.clone()))
            .collect::<Vec<_>>();
        let exact_prune_summary = late_step_exact_prune_family_summary(&prefix, 13, usize::MAX);
        let zero_admitted_summary =
            late_step_zero_admitted_failure_summary(&prefix, 13, usize::MAX);
        let connectivity_summary = late_step_terminal_connectivity_summary(&prefix, 13, usize::MAX);

        assert_eq!(step_thirteen.incremental_connectivity_prunes, 576);
        assert_eq!(step_thirteen.incremental_terminal_clause_filter_prunes, 0);
        assert_eq!(step_thirteen.incremental_terminal_rank_prunes, 0);
        assert_eq!(step_thirteen.incremental_terminal_prefix_bar_prunes, 0);
        assert_eq!(step_thirteen.incremental_partial_prefix_bound_prunes, 0);
        assert_eq!(
            exact_prune_summary,
            LateStepExactPruneFamilySummary {
                raw_generated_surface: 2320,
                roots_seen: 5,
                roots_enqueued: 5,
                partial_prefix_bound_prunes: 0,
                captured_prefixes: 135,
                cached_bound_count: 0,
                family_counts: BTreeMap::from([((0_usize, None, None), 135_usize)]),
            }
        );
        assert_eq!(
            zero_admitted_summary,
            LateStepZeroAdmittedFailureSummary {
                captured_prefixes: 135,
                generated_candidates: 270,
                disconnected_candidates: 270,
                trivially_derivable_rejections: 0,
                other_exact_legality_rejections: 0,
                structural_debt_cap_rejections: 0,
                all_disconnected_prefixes: 135,
                trivially_derivable_only_prefixes: 0,
                mixed_disconnect_and_trivial_prefixes: 0,
                other_rejection_prefixes: 0,
                reason_counts: BTreeMap::new(),
            }
        );
        assert_eq!(
            connectivity_summary,
            LateStepTerminalConnectivitySummary {
                captured_prefixes: 135,
                generated_candidates: 270,
                prune_disconnected_candidates: 270,
                needs_fallback_candidates: 0,
                keep_without_fallback_candidates: 0,
                structurally_disconnected_candidates: 270,
                structurally_connected_but_unqualified_candidates: 0,
                structurally_connected_via_historical_reanchor_candidates: 0,
            }
        );
    }

    fn repaired_claim_step_twelve_library_and_history() -> (Library, Vec<DiscoveryRecord>) {
        let claim_steps = super::search_bootstrap_prefix_for_profile_with_runtime(
            11,
            2,
            SearchProfile::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
        )
        .expect("claim prefix through step 11 should build");
        let claim_prefix = claim_steps
            .iter()
            .map(|step| step.telescope.clone())
            .collect::<Vec<_>>();
        let (mut library, mut history, _) = history_from_prefix(&claim_prefix);
        let mut progress_observer = None;
        let step_twelve = super::search_next_step(
            12,
            2,
            &library,
            &history,
            AdmissibilityMode::DesktopClaimShadow,
            crate::diversify::FrontierRuntimeLimits::unlimited(),
            None,
            &mut progress_observer,
        )
        .expect("live claim step 12 should build");
        history.push(DiscoveryRecord::new(
            12,
            u32::from(step_twelve.accepted.nu),
            u32::from(step_twelve.accepted.clause_kappa),
        ));
        library.push(LibraryEntry::from_telescope(
            &step_twelve.telescope,
            &library,
        ));
        (library, history)
    }

    fn continue_late_path_from_candidate(
        step_index: u32,
        end_step: u32,
        library: &Library,
        history: &[DiscoveryRecord],
        candidate: &crate::expand::ExpandedCandidate,
    ) -> Vec<(u32, String, u16, u16, usize)> {
        let mut next_history = history.to_vec();
        next_history.push(DiscoveryRecord::new(
            step_index,
            u32::from(candidate.nu),
            u32::from(candidate.clause_kappa),
        ));
        let mut next_library = library.clone();
        next_library.push(LibraryEntry::from_telescope(&candidate.telescope, library));
        let mut late_steps = Vec::new();
        for next_step_index in (step_index + 1)..=end_step {
            let mut progress_observer = None;
            let next_step = super::search_next_step(
                next_step_index,
                2,
                &next_library,
                &next_history,
                AdmissibilityMode::DesktopClaimShadow,
                crate::diversify::FrontierRuntimeLimits::unlimited(),
                None,
                &mut progress_observer,
            )
            .expect("late continuation should build");
            late_steps.push((
                next_step_index,
                next_step.accepted.candidate_hash.clone(),
                next_step.accepted.nu,
                next_step.accepted.clause_kappa,
                next_step.demo_funnel.generated_raw_prefixes,
            ));
            next_history.push(DiscoveryRecord::new(
                next_step_index,
                u32::from(next_step.accepted.nu),
                u32::from(next_step.accepted.clause_kappa),
            ));
            next_library.push(LibraryEntry::from_telescope(
                &next_step.telescope,
                &next_library,
            ));
        }
        late_steps
    }

